INSERT INTO public.departments (id, name_en, name_hi, website) VALUES ('86bbc815-60b5-46f2-80ce-7b5f03b8a3d7', 'Ministry of Micro, Small and Medium Enterprises (MSME); implemented via KVIC nodal agency and, in Bihar, through State KVIC Directorate, Bihar KVIB and District Industries Centres (DICs) and banks', 'सूक्ष्म, लघु एवं मध्यम उद्यम मंत्रालय (MSME); KVIC के माध्यम से, बिहार में राज्य KVIC निदेशालय, बिहार KVIB एवं जिला उद्योग केंद्रों द्वारा कार्यान्वित', NULL);
