INSERT INTO public.departments (id, name_en, name_hi, website) VALUES ('63ae0f53-396e-45ad-a075-91a929575767', 'Government of Bihar (Cabinet-approved; implemented via district administration / DM-led committees)', 'बिहार सरकार (कैबिनेट द्वारा स्वीकृत; जिला प्रशासन / डीएम की अध्यक्षता वाली समितियों द्वारा क्रियान्वित)', NULL);
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('6edd4646-1334-4f6e-8a77-aad392ba30dd', 'Atal Pension Yojana (APY)', 'अटल पेंशन योजना (APY)', '76bf5c89-0e98-4a01-98ff-d0de1281611f', NULL, 'Guaranteed minimum pension for workers, especially in the unorganised sector.', 'श्रमिकों, विशेषकर असंगठित क्षेत्र, हेतु गारंटीशुदा न्यूनतम पेंशन।', 'Indian citizens aged 18–40 with a bank account (non-income-tax-payers).', '18–40 आयु के भारतीय नागरिक जिनके पास बैंक खाता हो (गैर-आयकरदाता)।', 'Guaranteed pension', 'Guaranteed pension of ₹1,000–₹5,000/month after age 60 based on contribution. Income-tax payers are not eligible (since Oct 2022).', 'Unorganised-sector workers (18–40).', 'https://www.npscra.nsdl.co.in', 'active', 'Active — PFRDA confirms it is operational and enrolling (~9.1 crore subscribers by May 2026, a record ~1.35 crore added in FY2025-26). Age 18–40. Verified 2026-06-19. Source: https://www.pfrda.org.in/', NULL, NULL, 'https://www.npscra.nsdl.co.in', '2026-06-19', NULL, '2026-06-19 18:09:43.704208+05:30', '{worker_labourer}', '{}', 'any', '{}', 18, 40, NULL, false, 'any', false, false, NULL, NULL, '{social_welfare,financial_inclusion}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('94cb7a81-3162-432c-be8f-857233e39993', 'Bihar e-Kalyan Scholarship', 'बिहार ई-कल्याण छात्रवृत्ति', '3df327f2-b1bf-440d-a46f-840341a10329', NULL, 'Post-matric scholarships for SC/ST/BC/EBC and minority students pursuing higher studies.', 'उच्च शिक्षा हेतु SC/ST/BC/EBC एवं अल्पसंख्यक विद्यार्थियों के लिए पोस्ट-मैट्रिक छात्रवृत्ति।', 'Bihar-resident SC/ST/BC/EBC/minority students from Class 11 to PhD; income limits apply per category (verify at e-Kalyan).', 'बिहार निवासी SC/ST/BC/EBC/अल्पसंख्यक विद्यार्थी, कक्षा 11 से पीएचडी तक; श्रेणी अनुसार आय-सीमा (e-Kalyan पर सत्यापित करें)।', 'Scholarship', 'Tuition fees + annual maintenance (reported ₹2,000–₹25,000+/year by level). Verify current rates at the portal.', 'SC/ST/BC/EBC/minority students of Bihar.', 'https://www.ekalyan.bih.nic.in', 'active', 'Active — Bihar Post-Matric Scholarship (SC/ST/BC/EBC) operational for 2025-26 (fresh applications ~Sept–Nov 2025, correction window to 25 Dec 2025). Tuition + maintenance, Class 11 to graduation/PG/professional. Income limit ₹2.5 lakh for BC/EBC; no income bar for SC/ST. For 2025-26, post-matric applications run via pmsonline.bihar.gov.in; status/history via e-Kalyan. Verified 2026-06-19. Source: https://ekalyan.bih.nic.in/', NULL, NULL, 'https://www.ekalyan.bih.nic.in', '2026-06-19', NULL, '2026-06-19 17:38:29.821609+05:30', '{student}', '{senior_secondary}', 'any', '{sc,st,bc,ebc}', NULL, NULL, NULL, false, 'bihar', false, false, NULL, NULL, '{education}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('48e483eb-00e4-4621-92fb-7649318d43fd', 'Bihar Jal Jeevan Mission (Har Ghar Nal Ka Jal)', 'बिहार जल जीवन मिशन (हर घर नल का जल)', '90c44636-2a3e-437d-a8e3-ec1852f9d5ab', NULL, 'Functional piped tap-water connection to every rural household.', 'प्रत्येक ग्रामीण घर को कार्यशील पाइप जल कनेक्शन।', 'Rural households of Bihar lacking piped water (SC/ST/BPL free).', 'पाइप जल से वंचित बिहार के ग्रामीण घर (SC/ST/BPL नि:शुल्क)।', 'Piped water connection', 'Functional tap connection; free for SC/ST/BPL, nominal for others. Verify current terms.', 'Rural households of Bihar.', 'https://phedcgrc.in/', 'active', 'Active — Jal Jeevan Mission extended to Dec 2028 (JJM 2.0, Cabinet approval Mar 2026); Bihar at ~96% functional tap-connection coverage. Verified 2026-06-19. Source: https://jaljeevanmission.gov.in/', NULL, NULL, 'https://phedcms.bihar.gov.in', '2026-06-19', NULL, '2026-06-19 17:38:29.855315+05:30', '{}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'bihar', false, false, NULL, NULL, '{social_welfare,health}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('25a033c6-ed0c-4115-b314-cab068b2565c', 'Bihar Krishi Input Anudan Yojana', 'बिहार कृषि इनपुट अनुदान योजना', '77fa7e43-0589-4b9b-8807-bbafc0146d67', NULL, 'Input subsidy to farmers whose crops are damaged (33% or more) by flood, drought, hailstorm or unseasonal rain.', 'बाढ़, सूखा, ओलावृष्टि या बेमौसम वर्षा से 33% या अधिक फसल क्षति झेलने वाले किसानों को इनपुट अनुदान।', 'Permanent-resident farmers of Bihar (both Raiyat and Non-Raiyat) registered on the Agriculture DBT portal, whose crops suffered 33% or more damage. Typically capped at 2 hectares per farmer.', 'बिहार के स्थायी-निवासी किसान (रैयत एवं गैर-रैयत दोनों) जो कृषि DBT पोर्टल पर पंजीकृत हों एवं जिनकी फसल को 33% या अधिक क्षति हुई हो। सामान्यतः प्रति किसान 2 हेक्टेयर तक।', 'Input subsidy (DBT)', 'Per-hectare subsidy on 33%+ crop loss: ₹8,500 (un-irrigated), ₹17,000 (irrigated), ₹22,500 (perennial), up to ~2 hectares.', 'Farmers of Bihar with crop loss.', 'https://dbtagriculture.bihar.gov.in', 'active', 'Active — official dbtagriculture.bihar.gov.in shows Krishi Input Anudan open for Rabi 2025-26 (application 20–24 Jun 2026 across 5 districts) and publishes the Kharif 2025-26 implementation guidelines — a current-FY signal. Per-hectare on 33%+ loss: ₹8,500 (un-irrigated) / ₹17,000 (irrigated) / ₹22,500 (perennial), up to ~2 hectares. Verified 2026-06-19. Source: https://dbtagriculture.bihar.gov.in/', NULL, NULL, 'https://dbtagriculture.bihar.gov.in', '2026-06-19', NULL, '2026-06-19 14:17:34.336447+05:30', '{farmer}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'bihar', false, false, 'any', NULL, '{agriculture}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('f7c5289f-b2a2-4f97-ad8d-11221722362b', 'Bihar Krishi Yantra Anudan Yojana', 'बिहार कृषि यंत्र अनुदान योजना', '77fa7e43-0589-4b9b-8807-bbafc0146d67', NULL, 'Subsidy to farmers for purchasing farm machinery and equipment.', 'कृषि यंत्र व उपकरण खरीदने हेतु किसानों को अनुदान।', 'Farmers of Bihar registered on the Agriculture DBT portal.', 'कृषि DBT पोर्टल पर पंजीकृत बिहार के किसान।', 'Equipment subsidy', 'Subsidy (commonly up to ~80–90% for priority categories) on ~91 types of farm implements; applied via the OFMAS / DBT Agriculture portal in a seasonal window.', 'Farmers of Bihar.', 'https://farmech.bihar.gov.in/', 'active', 'Active — Bihar''s 2026-27 budget allocates ₹176 cr to agricultural mechanisation (PRS); the OFMAS portal (farmech.bihar.gov.in) is live and linked from the DBT Agriculture portal. Applications are seasonal. Verified 2026-06-19. Source: https://dbtagriculture.bihar.gov.in/', NULL, NULL, 'https://farmech.bih.nic.in', '2026-06-19', NULL, '2026-06-19 17:38:29.849615+05:30', '{farmer}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'bihar', false, false, 'any', NULL, '{agriculture}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('a8116e50-1c54-49b0-afef-ed7f8f528a3a', 'Bihar Laghu Udyami Yojana', 'बिहार लघु उद्यमी योजना', '656e1179-0bc5-45c0-b0b2-da0acbce5907', NULL, '₹2 lakh capital support to very poor families across all communities to start a small business / self-employment.', 'सभी समुदायों के अत्यंत निर्धन परिवारों को लघु व्यवसाय/स्वरोज़गार हेतु ₹2 लाख पूंजी सहायता।', 'Bihar resident aged 18–50 from a family with monthly income below ₹6,000 (all categories — General/OBC/SC/ST/Minority). Requires a current-year Bihar residence certificate.', 'बिहार निवासी, आयु 18–50, जिसके परिवार की मासिक आय ₹6,000 से कम हो (सभी श्रेणियाँ)। चालू वर्ष का आवासीय प्रमाण-पत्र आवश्यक।', 'Capital subsidy (grant)', '₹2 lakh as a 100% subsidy (no repayment), released in three installments (25% / 50% / 25%). For families with monthly income below ₹6,000.', 'Very poor families of Bihar (monthly income < ₹6,000).', 'https://udyami.bihar.gov.in', 'active', 'Active — hosted on the official udyami.bihar.gov.in portal; FY2025-26 cycle closed 23 Mar 2026 (selection by computerised randomisation), with current beneficiary notices (June 2026). ₹2 lakh 100% grant in three installments to families with monthly income below ₹6,000; all social categories, age 18–50. Verified 2026-06-19. Source: https://udyami.bihar.gov.in/', NULL, NULL, 'https://udyami.bihar.gov.in', '2026-06-19', NULL, '2026-06-19 14:17:34.334889+05:30', '{self_employed_entrepreneur}', '{}', 'any', '{}', 18, 50, 72000, false, 'bihar', false, false, NULL, NULL, '{financial_inclusion,industry}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('2d0b3afc-966d-40c1-9e5e-13d680730bb3', 'Janani Suraksha Yojana (JSY)', 'जननी सुरक्षा योजना', 'f99905da-40dd-4df9-93cc-4c6acb3516e1', NULL, 'Reduce maternal and neonatal mortality by promoting institutional delivery among poor pregnant women through conditional cash assistance.', 'गरीब गर्भवती महिलाओं में संस्थागत प्रसव को बढ़ावा देकर मातृ एवं नवजात मृत्यु-दर घटाना, सशर्त नकद सहायता के माध्यम से।', 'Bihar is classified as a Low Performing State, so all pregnant women delivering in a government health centre (Sub Centre/PHC/CHC) are eligible (in High Performing States only BPL/SC/ST women qualify). ASHA acts as the link facilitating the delivery.', 'बिहार ''कम-प्रदर्शन राज्य'' है, अतः सरकारी स्वास्थ्य केंद्र में प्रसव कराने वाली सभी गर्भवती महिलाएँ पात्र हैं। ASHA प्रसव में सहायता करती है।', 'cash transfer', 'Cash transfer on institutional delivery. In Low Performing States (which include Bihar): ₹1,400 to a rural mother + ₹600 to ASHA; ₹1,000 to an urban mother + ₹400 to ASHA. Entire entitlement disbursed to the mother in one go at the health institution.', 'Pregnant women (institutional delivery)', NULL, 'active', 'Fetched the NHM/MoHFW JSY page (nhm.gov.in, level=3 lid=309), which describes JSY as a current 100% centrally-sponsored NHM scheme with active cash-assistance amounts and special focus on Bihar as a Low Performing State. State Health Society Bihar maintains a live JSY maternal-health programme page (shs.bihar.gov.in) confirming state implementation. Could not pull an exact current-FY Bihar budget figure, but it is an ongoing core NHM intervention.', NULL, NULL, 'https://nhm.gov.in/index1.php?lang=1&level=3&lid=309&sublinkid=841', '2026-06-22', NULL, '2026-06-22 12:27:36.779072+05:30', '{pregnant_lactating_woman}', '{}', 'female', '{}', NULL, NULL, NULL, false, 'any', false, false, NULL, NULL, '{health,women_child}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('fb764b80-c87b-493b-a427-1be43c71dc76', 'Bihar Alpsankhyak Rozgar Rin Yojana', 'बिहार अल्पसंख्यक रोज़गार ऋण योजना', '60f63e90-1ce6-4a9d-bd97-ae836d1ee9dd', NULL, 'Low-interest business loans for minority-community entrepreneurs.', 'अल्पसंख्यक समुदाय के उद्यमियों हेतु कम-ब्याज व्यवसाय ऋण।', 'Minority-community residents of Bihar aged 18–50 starting/expanding a business.', 'बिहार के अल्पसंख्यक समुदाय के निवासी, आयु 18–50, व्यवसाय हेतु।', 'Business loan', 'Self-employment loan up to ₹5 lakh at 5% simple interest (with a 0.5% rebate for timely repayment), repaid over 5 years, for minority-community members.', 'Minority entrepreneurs of Bihar.', 'https://state.bihar.gov.in/minoritywelfare', 'likely_active', 'Likely active — listed by BSMFC and myScheme, but the latest official sanction lists are FY2021-22 with no new 2024-26 cycle confirmed. [Corrected: flat 5% (no separate women''s rate); ceiling ₹5 lakh; family income ≤₹4 lakh/yr.] Verified 2026-06-19. Source: https://bsmfc.org/', NULL, NULL, 'https://state.bihar.gov.in/minoritywelfare', '2026-06-19', NULL, '2026-06-19 17:38:29.842118+05:30', '{self_employed_entrepreneur}', '{}', 'any', '{minority}', 18, 50, 400000, false, 'bihar', false, false, NULL, NULL, '{financial_inclusion,employment}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('89df8456-e35a-4a46-be74-274a0df7a8d5', 'Bihar Mukhyamantri Bagwani Mission', 'बिहार मुख्यमंत्री बागवानी मिशन', '77fa7e43-0589-4b9b-8807-bbafc0146d67', NULL, 'Subsidy support for horticulture — fruit and vegetable cultivation.', 'बागवानी — फल व सब्ज़ी की खेती हेतु अनुदान सहायता।', 'Farmers of Bihar undertaking horticulture cultivation.', 'बागवानी करने वाले बिहार के किसान।', 'Cultivation subsidy', 'Reported up to 50% subsidy (₹15,000–₹1,00,000/ha by crop). Verify current rates.', 'Horticulture farmers of Bihar.', 'https://horticulture.bihar.gov.in/MainSite/SchemeDetails_CMHM.aspx', 'active', 'Active — the official CMHM horticulture portal is live with a 2025-26 application year and 2025/2026-dated notices; subsidy up to ~50% varies by component. Verified 2026-06-19. Source: https://horticulture.bihar.gov.in/MainSite/SchemeDetails_CMHM.aspx', NULL, NULL, 'https://horticulture.bihar.gov.in', '2026-06-19', NULL, '2026-06-19 17:38:29.850643+05:30', '{farmer}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'bihar', false, false, 'any', NULL, '{agriculture}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('2842be35-11e5-44db-bbc3-d594c8852a03', 'Bihar Mukhyamantri Gram Parivahan Yojana', 'बिहार मुख्यमंत्री ग्राम परिवहन योजना', '3df327f2-b1bf-440d-a46f-840341a10329', NULL, 'Subsidy to rural SC/ST/EBC youth to buy a passenger vehicle for transport livelihood.', 'ग्रामीण SC/ST/EBC युवाओं को यात्री वाहन खरीदने हेतु अनुदान।', 'Rural SC/ST/EBC residents of Bihar.', 'बिहार के ग्रामीण SC/ST/EBC निवासी।', 'Vehicle subsidy', '50% subsidy, capped at ₹1 lakh (standard 3/4-wheeler), ₹70,000 (e-rickshaw) or ₹2 lakh (ambulance), for SC/ST/EBC groups.', 'Rural SC/ST/EBC youth.', 'https://state.bihar.gov.in/transport', 'likely_active', 'Likely active — listed on the Bihar Transport Dept portal and myScheme and run phase-wise, but the latest hard figures are older (43,917 beneficiaries to Mar 2023) with no current-FY notification found. [Corrected: SC/ST/EBC only; tiered caps.] Verified 2026-06-19. Source: https://state.bihar.gov.in/transport/', NULL, NULL, 'https://state.bihar.gov.in/transport', '2026-06-19', NULL, '2026-06-19 17:38:29.844496+05:30', '{self_employed_entrepreneur}', '{}', 'any', '{sc,st,ebc}', NULL, NULL, NULL, false, 'bihar', false, false, NULL, NULL, '{employment,social_welfare}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('3938f44b-9e4b-4085-b0ee-5f5a86cd1d1b', 'Bihar Mukhyamantri Gramin Awas Yojana', 'बिहार मुख्यमंत्री ग्रामीण आवास योजना', '2c5ae0d5-a340-4379-bcf0-f008c2796f74', NULL, 'Assistance to rural poor families without a pucca house to build one.', 'पक्के मकान से वंचित ग्रामीण निर्धन परिवारों को आवास निर्माण हेतु सहायता।', 'Rural BPL families of Bihar without a pucca house.', 'पक्के मकान से वंचित बिहार के ग्रामीण BPL परिवार।', 'Housing assistance (DBT)', 'Unit assistance of ₹1.20 lakh (₹1.30 lakh in 11 IAP districts) in milestone installments plus MGNREGA wage days, for rural families excluded from PMAY-G.', 'Rural BPL families of Bihar.', 'https://state.bihar.gov.in/rdd/', 'likely_active', 'Likely active — listed on myScheme as a Bihar Rural Development Dept scheme for PMAY-G-excluded families; no current-FY state budget line or notice fetched, so not upgraded to active. Verified 2026-06-19. Source: https://www.myscheme.gov.in/schemes/mgawb', NULL, NULL, 'https://rdd.bihar.gov.in', '2026-06-19', NULL, '2026-06-19 17:38:29.853134+05:30', '{}', '{}', 'any', '{}', NULL, NULL, NULL, true, 'bihar', false, false, NULL, NULL, '{housing,social_welfare}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('48fff497-33a9-4713-ba5e-17941ea8ecce', 'Bihar Mukhyamantri Niji Nalkoop Yojana', 'मुख्यमंत्री निजी नलकूप योजना', '77fa7e43-0589-4b9b-8807-bbafc0146d67', NULL, 'Subsidy to farmers for installing private tubewells for irrigation.', 'सिंचाई हेतु निजी नलकूप लगाने के लिए किसानों को अनुदान।', 'Farmers of Bihar (Raiyat/non-Raiyat) needing irrigation; minimum landholding criteria may apply.', 'सिंचाई हेतु इच्छुक बिहार के किसान (रैयत/गैर-रैयत); न्यूनतम भूधारिता मानदंड लागू हो सकते हैं।', 'Tubewell subsidy', 'Reported 50–80% subsidy (₹15,000–₹35,000 per farmer). Verify current rates.', 'Farmers of Bihar needing irrigation.', 'https://mwrd.bihar.gov.in/mnny/', 'likely_active', 'Likely active — the official Minor Water Resources portal runs the Mukhyamantri Niji Nalkoop Yojana under Saat Nishchay-2 (target 35,000 borewells); ''Shatabdi Niji Nalkoop'' is an older label. No current open-application window confirmed, so not upgraded to active. Verified 2026-06-19. Source: https://mwrd.bihar.gov.in/mnny/', NULL, NULL, 'https://mwrd.bihar.gov.in', '2026-06-19', NULL, '2026-06-19 17:50:07.60627+05:30', '{farmer}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'bihar', false, false, 'any', NULL, '{agriculture}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('e09c0707-ac7d-4904-8476-7ef3a55617e3', 'Bihar Nishulk Coaching Yojana', 'बिहार नि:शुल्क कोचिंग योजना', '3df327f2-b1bf-440d-a46f-840341a10329', NULL, 'Free competitive-exam coaching for SC/ST/EBC/OBC/minority students from low-income families.', 'निम्न-आय परिवारों के SC/ST/EBC/OBC/अल्पसंख्यक विद्यार्थियों हेतु नि:शुल्क प्रतियोगी-परीक्षा कोचिंग।', 'Bihar-resident SC/ST/EBC/OBC/minority students with family income below ₹3 lakh/year.', 'बिहार निवासी SC/ST/EBC/OBC/अल्पसंख्यक विद्यार्थी जिनकी पारिवारिक आय ₹3 लाख/वर्ष से कम हो।', 'Free coaching + stipend', 'Free competitive-exam (UPSC/BPSC/SSC) coaching with a monthly stipend (reported ₹1,500 for local / ₹3,000 for outstation students).', 'Low-income SC/ST/EBC/OBC/minority students.', 'https://state.bihar.gov.in/socialwelfare', 'likely_active', 'Likely active — Bihar free-coaching programs reported open in 2025 via Pre-Examination Training Centres; an umbrella of department-specific programs (the prominent one run by the BC/EBC Welfare Department). Stipend reported, not officially published. Verified 2026-06-19. Source: https://bcebconline.bihar.gov.in/', NULL, NULL, 'https://state.bihar.gov.in/socialwelfare', '2026-06-19', NULL, '2026-06-19 17:38:29.837557+05:30', '{student}', '{}', 'any', '{sc,st,ebc,bc,minority}', NULL, NULL, 300000, false, 'bihar', false, false, NULL, NULL, '{education,skilling}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('c5077c59-c6df-4c2f-a0cc-667e8dd55968', 'Bihar Diesel Anudan Yojana', 'बिहार डीज़ल अनुदान योजना', '77fa7e43-0589-4b9b-8807-bbafc0146d67', NULL, 'Diesel subsidy to farmers for irrigating standing crops during dry spells.', 'सूखे के दौरान खड़ी फसलों की सिंचाई हेतु किसानों को डीज़ल अनुदान।', 'Farmers of Bihar (Raiyat/non-Raiyat) registered on the Agriculture DBT portal, during a notified drought/dry spell.', 'अधिसूचित सूखा/शुष्क अवधि में कृषि DBT पोर्टल पर पंजीकृत बिहार के किसान (रैयत/गैर-रैयत)।', 'Diesel subsidy (DBT)', 'Per-irrigation-round diesel subsidy (rate notified each season; reported ~₹750/acre per round, e.g. ~₹1,500/acre for paddy).', 'Farmers of Bihar during dry spells.', 'https://dbtagriculture.bihar.gov.in', 'active', 'Active — the official DBT Agriculture portal listed Diesel Subsidy (Kharif) 2025-26 with a 31 Jul–30 Oct 2025 window; runs each season. Verified 2026-06-19. Source: https://dbtagriculture.bihar.gov.in/', NULL, NULL, 'https://dbtagriculture.bihar.gov.in', '2026-06-19', NULL, '2026-06-19 17:50:07.609037+05:30', '{farmer}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'bihar', false, false, 'any', NULL, '{agriculture}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('961d412f-288a-462f-958e-f46af85ff79a', 'Bihar Parvarish Yojana', 'बिहार परवरिश योजना', '3df327f2-b1bf-440d-a46f-840341a10329', NULL, 'Monthly maintenance for orphans, semi-orphans and children of HIV-positive or severely disabled parents.', 'अनाथ, अर्ध-अनाथ एवं HIV-संक्रमित या गंभीर दिव्यांग माता-पिता के बच्चों हेतु मासिक भरण-पोषण।', 'Eligible vulnerable children of Bihar up to age 18 (per scheme criteria).', 'योजना मानदंड अनुसार बिहार के पात्र संवेदनशील बच्चे, 18 वर्ष तक।', 'Monthly maintenance (DBT)', '₹1,000/month per eligible child (0–18) — orphans, HIV/leprosy/cancer-affected, and children of widows or disabled parents. Paid via DBT.', 'Orphans/vulnerable children of Bihar.', 'https://esuvidha.bihar.gov.in', 'active', 'Active — listed on myScheme and shown as payable on Bihar''s e-Suvidha portal (Mar 2026). Verified 2026-06-19. Source: https://www.myscheme.gov.in/schemes/pybihar', NULL, NULL, 'https://state.bihar.gov.in/socialwelfare', '2026-06-19', NULL, '2026-06-19 17:38:29.85137+05:30', '{}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'bihar', false, false, NULL, NULL, '{social_welfare,women_child}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('dd096773-31eb-4544-975d-39b3fd7c1948', 'Ayushman Bharat — PM-JAY', 'आयुष्मान भारत — पीएम-जय', '76bf5c89-0e98-4a01-98ff-d0de1281611f', NULL, 'Health insurance cover for hospitalisation to eligible low-income families.', 'पात्र निम्न-आय परिवारों को अस्पताल में भर्ती हेतु स्वास्थ्य बीमा।', 'Families identified as eligible (SECC deprivation criteria / state-extended lists). Check eligibility on the PM-JAY portal.', 'पात्र पहचाने गए परिवार (SECC वंचना मानदंड / राज्य-विस्तारित सूची)। पात्रता PM-JAY पोर्टल पर जाँचें।', 'Health insurance', 'Cover up to ₹5 lakh per family per year for secondary/tertiary hospitalisation. The Ayushman Vay Vandana extension additionally covers all citizens aged 70+ regardless of income.', 'Eligible low-income families.', 'https://pmjay.gov.in', 'active', 'Active in Bihar — official reports cite >₹1,000 crore saved by Bihar beneficiaries in a year, with ongoing enrolment drives. ₹5 lakh/family/year (secondary/tertiary). The Ayushman Vay Vandana extension now covers all citizens aged 70+ regardless of income. Verified 2026-06-19. Source: https://pmjay.gov.in/', NULL, NULL, 'https://pmjay.gov.in', '2026-06-19', NULL, '2026-06-19 18:09:43.690873+05:30', '{}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'any', false, false, NULL, NULL, '{health,social_welfare}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('0ad1dc9c-451a-4ab4-a4e9-d0a531a166b3', 'Bihar Pravasi Majdoor Durghatna Bima Yojana', 'बिहार प्रवासी मज़दूर दुर्घटना बीमा योजना', '896891da-f714-41d6-b6bb-fd84e5ecfb00', NULL, 'Accident insurance cover for migrant workers from Bihar.', 'बिहार के प्रवासी मज़दूरों हेतु दुर्घटना बीमा।', 'Registered migrant workers from Bihar.', 'बिहार के पंजीकृत प्रवासी मज़दूर।', 'Accident insurance', 'For migrant-worker accidents outside Bihar/abroad (within 180 days): ₹4 lakh on death, ₹1 lakh for permanent full disability, ₹50,000 for permanent partial disability — paid by RTGS.', 'Migrant workers of Bihar.', 'https://state.bihar.gov.in/labour', 'active', 'Active — amounts revised by the Bihar State Migrant Labour Accident Grant (Amendment) Rules, 2026 (S.O. 75, 9 Feb 2026): death ₹2L→₹4L, partial ₹75k→₹50k. Verified 2026-06-19. Source: https://serviceonline.bihar.gov.in/', NULL, '2026-02-09', 'https://state.bihar.gov.in/labour', '2026-06-19', NULL, '2026-06-19 17:38:29.84554+05:30', '{worker_labourer}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'bihar', false, false, NULL, NULL, '{social_welfare,employment}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('5d03c1b2-2c06-43c2-ba44-243329a61b2b', 'Bihar Rajya Fasal Sahayata Yojana', 'बिहार राज्य फसल सहायता योजना', '77fa7e43-0589-4b9b-8807-bbafc0146d67', NULL, 'Financial assistance to farmers for crop loss from natural calamities (state crop-protection scheme).', 'प्राकृतिक आपदाओं से फसल क्षति पर किसानों को वित्तीय सहायता (राज्य फसल-सुरक्षा योजना)।', 'Raiyat and non-Raiyat farmers of Bihar registered for the scheme.', 'योजना हेतु पंजीकृत बिहार के रैयत व गैर-रैयत किसान।', 'Crop-loss assistance', 'Reported ₹7,500/ha (loss up to 20%) or ₹10,000/ha (loss above 20%), up to 2 hectares per farmer. Verify current-season rates.', 'Farmers of Bihar with crop loss.', 'https://pacsonline.bih.nic.in', 'likely_active', 'Likely active — the official FSY portal (pacsonline.bih.nic.in/fsy) is the live registration system and the scheme runs each season (Kharif 2025 window ~20 Aug–31 Oct 2025). Reported ₹7,500/ha (loss ≤20%) / ₹10,000/ha (loss >20%), up to 2 hectares. No current-season official notification was fetched, so not upgraded to active. Verified 2026-06-19. Source: https://pacsonline.bih.nic.in/fsy/login.aspx', NULL, NULL, 'https://pacsonline.bih.nic.in', '2026-06-19', NULL, '2026-06-19 17:38:29.848588+05:30', '{farmer}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'bihar', false, false, 'any', NULL, '{agriculture}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('0fd87983-5e61-4ba0-be9d-cd7247ac1339', 'Bihar Scholarship Portal (Pre/Post-Matric)', 'बिहार छात्रवृत्ति पोर्टल (प्री/पोस्ट-मैट्रिक)', '3df327f2-b1bf-440d-a46f-840341a10329', NULL, 'Pre- and post-matric scholarships for SC/ST/BC/EBC students across school and college levels.', 'विद्यालय व महाविद्यालय स्तर पर SC/ST/BC/EBC विद्यार्थियों हेतु प्री व पोस्ट-मैट्रिक छात्रवृत्ति।', 'Bihar-resident SC/ST/BC/EBC students; class and category-based rates; income limits apply.', 'बिहार निवासी SC/ST/BC/EBC विद्यार्थी; कक्षा व श्रेणी आधारित दरें; आय-सीमा लागू।', 'Scholarship', 'Reported ₹1,000–₹15,000+/year depending on class and category. Verify at the portal.', 'SC/ST/BC/EBC students of Bihar.', 'https://pmsonline.bihar.gov.in', 'active', 'Active — SC/ST and BC/EBC pre/post-matric scholarships ran for 2025-26 (applications/correction windows open into late 2025). SC/ST via scstpmsonline.bihar.gov.in, BC/EBC via pmsonline.bihar.gov.in. Verified 2026-06-19. Source: https://pmsonline.bihar.gov.in/', NULL, NULL, 'https://www.ekalyan.bih.nic.in', '2026-06-19', NULL, '2026-06-19 17:38:29.829766+05:30', '{student}', '{}', 'any', '{sc,st,bc,ebc}', NULL, NULL, NULL, false, 'bihar', false, false, NULL, NULL, '{education}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('1561278c-1502-4320-b147-272d0436c9b5', 'Bihar Startup Fund (Seed Funding)', 'बिहार स्टार्टअप फंड (सीड फंडिंग)', '656e1179-0bc5-45c0-b0b2-da0acbce5907', NULL, 'Seed capital and support for innovative early-stage startups registered and operating in Bihar.', 'बिहार में पंजीकृत व संचालित नवाचारी प्रारंभिक-चरण स्टार्टअप हेतु सीड पूंजी एवं सहायता।', 'A startup registered and operating in Bihar with an innovative, scalable business model (per the Bihar Startup Policy 2022). Founder eligibility and registration details to be confirmed at the portal.', 'बिहार में पंजीकृत व संचालित स्टार्टअप जिसका व्यवसाय मॉडल नवाचारी व मापनीय हो (बिहार स्टार्टअप नीति 2022 अनुसार)। संस्थापक पात्रता व पंजीकरण विवरण पोर्टल से पुष्टि करें।', 'Interest-free seed loan + grant', 'Interest-free seed-funding loan up to ₹10 lakh (10-year repayment), with enhancements for women and SC/ST/PwD founders, under the Bihar Startup Policy 2022.', 'Early-stage startups in Bihar.', 'https://startup.bihar.gov.in', 'active', 'Active — the startup.bihar.gov.in portal is live (updated Jun 2026) and SIDBI manages a ₹50 cr Bihar scale-up fund (Jun 2026); ~₹52+ cr disbursed to 900+ startups. [Note: a separate ₹3 lakh grant could not be officially confirmed.] Verified 2026-06-19. Source: https://startup.bihar.gov.in/', NULL, NULL, 'https://startup.bihar.gov.in', '2026-06-19', NULL, '2026-06-19 17:07:53.540539+05:30', '{self_employed_entrepreneur}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'bihar', false, true, NULL, NULL, '{industry,financial_inclusion}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('60b5e46e-52c6-42dd-9edf-f31e90ce41be', 'Bihar State Housing Board — Housing Allotment (e-Lottery)', 'बिहार राज्य आवास बोर्ड — आवास आवंटन (ई-लॉटरी)', 'f519f409-ac92-4faa-942b-312012c173cd', NULL, 'The Bihar State Housing Board (a statutory body established in 1972) develops integrated residential colonies — plots, flats and apartments across income categories (EWS / LIG / MIG / HIG) — and allots dwelling units to the public through a transparent online e-lottery. It also runs property e-auctions and lease-hold to free-hold conversion for existing allottees.', 'बिहार राज्य आवास बोर्ड (1972 में स्थापित एक सांविधिक निकाय) सभी आय वर्गों (EWS / LIG / MIG / HIG) हेतु एकीकृत आवासीय कॉलोनियाँ — भूखंड, फ्लैट एवं अपार्टमेंट — विकसित करता है तथा पारदर्शी ऑनलाइन ई-लॉटरी के माध्यम से आम जनता को आवास आवंटित करता है। यह संपत्ति की ई-नीलामी तथा मौजूदा आवंटियों हेतु लीज-होल्ड से फ्री-होल्ड रूपांतरण भी करता है।', 'Open to the general public across income categories (EWS / LIG / MIG / HIG). Income eligibility for a given unit is set by the prevailing policy and stated in each project''s advertisement / brochure. Key rule: if the applicant or any family member has already been allotted a dwelling unit or residential plot in any BSHB project, they are not eligible to apply again in a subsequent project. Applications are submitted online and units allotted by e-lottery.', 'सभी आय वर्गों (EWS / LIG / MIG / HIG) की आम जनता हेतु खुला। किसी इकाई के लिए आय पात्रता प्रचलित नीति द्वारा निर्धारित होती है और प्रत्येक परियोजना के विज्ञापन / विवरणिका में दी जाती है। मुख्य नियम: यदि आवेदक या उसके परिवार के किसी सदस्य को बोर्ड की किसी परियोजना में पहले ही आवास इकाई या भूखंड आवंटित हो चुका है, तो वह किसी बाद की परियोजना हेतु पुनः आवेदन के पात्र नहीं हैं। आवेदन ऑनलाइन जमा होते हैं और इकाइयाँ ई-लॉटरी द्वारा आवंटित की जाती हैं।', 'Housing allotment (plot / flat / apartment)', 'Allotment of a residential plot, flat or apartment in a Board-developed colony, priced by income category, via online application and e-lottery. EWS/LIG units are offered at subsidised rates. Existing allottees can apply for lease-hold to free-hold conversion; surplus/commercial units are sold through e-auction on the Bihar e-Procurement portal.', 'General public seeking housing across EWS / LIG / MIG / HIG income categories.', 'https://bshb.bihar.gov.in/', 'likely_active', 'Likely active — the Bihar State Housing Board (est. 1972) operates an active official portal (bshb.bihar.gov.in) carrying schemes, online application, e-auction and lease-to-freehold modules, and has ongoing procurement (300+ live e-tenders, plus a proposed residential complex at Ara under environmental clearance). No scheme-wise budget line is published for the Board (its allotment activity is largely self-financing), and a specific current allotment/e-lottery advertisement could not be confirmed at verification, so this is likely_active rather than active. Verified 2026-06-25.', NULL, NULL, 'https://bshb.bihar.gov.in/', '2026-06-25', NULL, '2026-06-25 16:28:47.522475+05:30', '{}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'any', false, false, NULL, NULL, '{housing,social_welfare}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('9233a93b-eb07-4594-aa14-025bd55742c7', 'Backward Regions Grant Fund (BRGF)', 'पिछड़ा क्षेत्र अनुदान निधि (BRGF)', '76bf5c89-0e98-4a01-98ff-d0de1281611f', NULL, 'Earlier central fund to redress regional development imbalances in backward districts.', 'पिछड़े ज़िलों में क्षेत्रीय विकास असंतुलन दूर करने हेतु पूर्ववर्ती केंद्रीय निधि।', 'Identified backward districts (historical programme).', 'चिह्नित पिछड़े ज़िले (ऐतिहासिक कार्यक्रम)।', 'District development grant', 'Provided untied grants to backward districts for development gaps.', 'Backward districts.', NULL, 'lapsed', 'Lapsed — the Backward Regions Grant Fund was delinked from central budgetary support from 2015-16 following the 14th Finance Commission (states'' tax share raised to 42%); no direct successor. Verified 2026-06-19. Source: https://cprindia.org/briefsreports/budget-brief-2015-16-backward-regions-grant-fund/', NULL, NULL, 'https://rural.gov.in', '2026-06-19', NULL, '2026-06-19 18:13:52.06585+05:30', '{}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'any', false, false, NULL, NULL, '{social_welfare}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('18096a75-4542-48ec-b769-f7a43e948004', 'Bihar Student Credit Card Scheme', 'बिहार स्टूडेंट क्रेडिट कार्ड योजना', 'b4cdf34b-599a-4ee4-9d31-cecac8488797', '2016-10-02', 'Financial support, through the banking system, for students from Bihar who have passed class 12 (Intermediate) but cannot pursue higher education due to financial constraints.', 'बैंकिंग प्रणाली के माध्यम से बिहार के उन विद्यार्थियों को वित्तीय सहायता जिन्होंने 12वीं (इंटरमीडिएट) उत्तीर्ण की है परन्तु आर्थिक कारणों से उच्च शिक्षा प्राप्त नहीं कर पा रहे हैं।', 'Permanent resident of Bihar who has passed Intermediate/class 12 from a Bihar government-recognised institution and intends to pursue higher education.', 'बिहार का स्थायी निवासी जिसने राज्य सरकार से मान्यता प्राप्त संस्थान से इंटरमीडिएट/12वीं उत्तीर्ण की हो और उच्च शिक्षा प्राप्त करना चाहता हो।', 'Education loan', 'Education loan up to ₹4 lakh for higher studies — now interest-free for all categories (Sept 2025 reform; previously 4% general / 1% for women & PwD). Repayment extended to 7 yrs (≤₹2L) or 10 yrs (>₹2L). Processed via the DRCC.', 'Students from Bihar who have passed class 12 and intend to pursue higher education.', 'https://www.7nishchay-yuvaupmission.bihar.gov.in/', 'active', 'Active — official 7nishchay portal lists it live (DRCC-processed). Loans made INTEREST-FREE for all categories from Sept 2025 (was 4% / 1%), with repayment extended to 7 yrs (≤₹2L) / 10 yrs (>₹2L). Up to ₹4 lakh, 12th-pass, age ≤25 (30 for postgraduate). Verified 2026-06-19. Source: https://www.7nishchay-yuvaupmission.bihar.gov.in/', '2025-26', NULL, 'https://www.7nishchay-yuvaupmission.bihar.gov.in/', '2026-06-19', NULL, '2026-06-18 19:41:39.095908+05:30', '{student}', '{senior_secondary}', 'any', '{}', NULL, NULL, NULL, false, 'bihar', false, false, NULL, NULL, '{education}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('3caee594-38b7-4e41-820b-2e4d2e93dcb7', 'Bihar Vaas Bhoomi Yojana', 'बिहार वास भूमि योजना', 'ecb9ef3c-bb67-4c87-956b-9e2dc887a8fa', NULL, 'Free homestead land to landless rural poor families (priority to Mahadalit/SC/ST).', 'भूमिहीन ग्रामीण निर्धन परिवारों को नि:शुल्क वास भूमि (महादलित/SC/ST को प्राथमिकता)।', 'Landless rural BPL families of Bihar without homestead land.', 'वास भूमि से वंचित बिहार के भूमिहीन ग्रामीण BPL परिवार।', 'Homestead land title', 'Free homestead plot of up to 5 decimal (basgeet parcha) to a landless family; where no government land is available, ₹1 lakh cash to buy a plot.', 'Landless rural BPL families.', 'https://state.bihar.gov.in/lrc/', 'active', 'Active — live campaign ''Abhiyan Basera-2'' (15–21 Jun 2026) allotting plots; the cash-purchase assistance was raised from ₹60,000 to ₹1 lakh (Prabhat Khabar, Jun 2026). Verified 2026-06-19. Source: https://state.bihar.gov.in/lrc/', NULL, NULL, 'https://state.bihar.gov.in/lrc', '2026-06-19', NULL, '2026-06-19 17:50:07.607758+05:30', '{}', '{}', 'any', '{sc,st}', NULL, NULL, NULL, true, 'bihar', false, false, NULL, NULL, '{housing,social_welfare}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('aeb20521-a747-42ca-a0a3-4c3f9b41659b', 'BSDM Domain Skilling Program (Bihar Skill Development Mission)', 'बिहार कौशल विकास मिशन - डोमेन स्किलिंग कार्यक्रम', 'f4b14117-0fb8-4a33-a23a-8916f6ebd415', NULL, 'Provide employment-linked, sector-specific (domain) vocational skill training to Bihar''s youth beyond the foundational Kushal Yuva Program, building a standardised, ICT-monitored skill ecosystem with placement facilitation; includes dedicated tracks for PwD/Divyangjan and transgender candidates.', 'कुशल युवा कार्यक्रम से आगे बढ़कर बिहार के युवाओं को रोजगार-संबद्ध, क्षेत्र-विशिष्ट (डोमेन) व्यावसायिक कौशल प्रशिक्षण देना, साथ ही प्लेसमेंट सहायता तथा दिव्यांग एवं ट्रांसजेंडर हेतु समर्पित ट्रैक।', 'Bihar-resident youth seeking sector-specific skilling (general domain skilling builds on KYP-type foundational eligibility); a dedicated PwD/Divyangjan and transgender track covers candidates aged 15-59. Apply via the BSDM portal.', 'क्षेत्र-विशिष्ट कौशल चाहने वाले बिहार-निवासी युवा; दिव्यांग/ट्रांसजेंडर हेतु समर्पित ट्रैक 15–59 आयु के अभ्यर्थियों को कवर करता है। BSDM पोर्टल पर आवेदन।', 'training', 'Free job-oriented domain/sector-specific skill training through empanelled Training Partners, government-recognised certification on completion, and placement assistance into relevant sectors. Dedicated PwD and transgender skilling tracks are being empanelled.', 'Bihar youth (sector skilling)', 'https://skillmissionbihar.org/', 'likely_active', 'Bihar Skill Development Mission''s official portal lists Domain Skilling as a flagship program alongside KYP; recent BSDM Requests for Proposal to empanel Training Partners for Domain Skilling and for PwD/Transgender skilling (RFP cycles up to 2026) indicate active procurement and ongoing operation. Current-FY budget allocation not separately confirmed from budget.bihar.gov.in, hence likely_active. Distinct from Kushal Yuva Program already in catalogue.', NULL, NULL, 'https://skillmissionbihar.org/domain-skilling/domain-based-fresh-skilling/schemes-under-domain-skilling', '2026-06-22', NULL, '2026-06-22 12:27:36.779072+05:30', '{unemployed_youth}', '{}', 'any', '{}', 15, NULL, NULL, false, 'bihar', false, false, NULL, NULL, '{skilling,employment}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('bb61e099-c700-4dea-aa56-3379acbf88d4', 'Chief Minister Medical Relief Fund (Bihar)', 'मुख्यमंत्री चिकित्सा सहायता कोष', 'd65dd7e5-0120-4645-b90e-9d92524ca396', NULL, 'Provide medical financial aid to Bihar residents for the treatment of certain serious ailments at empanelled hospitals, including treatment outside Bihar.', 'बिहार के निवासियों को कुछ गंभीर बीमारियों के उपचार हेतु, बिहार के बाहर सहित, सूचीबद्ध अस्पतालों में चिकित्सा वित्तीय सहायता प्रदान करना।', 'Bihar residents with annual family income less than ₹2,50,000, for treatment of certain serious ailments at CGHS-empanelled hospitals.', 'वार्षिक पारिवारिक आय 2,50,000 रु. से कम वाले बिहार निवासी, CGHS-सूचीबद्ध अस्पतालों में कुछ गंभीर बीमारियों के उपचार हेतु।', 'financial assistance', 'Medical financial assistance toward treatment of specified serious ailments at CGHS-empanelled hospitals (including hospitals outside Bihar, for which aid can be applied for and availed at Bihar Bhawan, New Delhi). Exact per-case ceiling and full disease list not stated on the page fetched.', 'Bihar residents (serious illness, income < ₹2.5L)', NULL, 'likely_active', 'Fetched the official Bihar Bhawan page (biharbhawan.gov.in/cmReliefFund.aspx), which is live and describes the income-based eligibility (income < ₹2.5 lakh), CGHS-empanelled-hospital treatment, an application route via Bihar Bhawan New Delhi, and active helplines (WhatsApp +91 8527595623; Jigyasa 0612-2233333). Marked likely_active rather than active because the page does not show a current budget line, the full covered-disease list, or the exact benefit ceiling — those were in a linked PDF I could not parse.', NULL, NULL, 'https://www.biharbhawan.gov.in/cmReliefFund.aspx', '2026-06-22', NULL, '2026-06-22 12:27:36.779072+05:30', '{}', '{}', 'any', '{}', NULL, NULL, 250000, false, 'bihar', false, false, NULL, NULL, '{health,social_welfare}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('27e2cd47-9776-406d-83a9-46add0d5a543', 'e-Shram (Unorganised Workers Registration)', 'ई-श्रम (असंगठित श्रमिक पंजीकरण)', '76bf5c89-0e98-4a01-98ff-d0de1281611f', NULL, 'National database & identity card for unorganised workers, linking them to welfare/social-security benefits.', 'असंगठित श्रमिकों हेतु राष्ट्रीय डेटाबेस व पहचान-पत्र, जो उन्हें कल्याण/सामाजिक-सुरक्षा लाभों से जोड़े।', 'Unorganised-sector workers aged 16–59 (non-EPF/ESIC, non-income-tax-payers).', '16–59 आयु के असंगठित श्रमिक (EPF/ESIC में नहीं, गैर-आयकरदाता)।', 'Registration + accident cover', 'An e-Shram card is registration/identity for unorganised workers and a gateway to linked welfare schemes (PMSBY, PMJJBY, PM-SYM, PDS, Ayushman, NSAP, etc.). It does not itself provide insurance — linked schemes require separate enrolment.', 'Unorganised-sector workers.', 'https://eshram.gov.in', 'active', 'Active — ~31 crore registrations by Aug 2025; mobile app launched Feb 2025; 14 schemes integrated (PIB). [Corrected: the card does not auto-provide accident cover.] Verified 2026-06-19. Source: https://eshram.gov.in/', NULL, NULL, 'https://eshram.gov.in', '2026-06-19', NULL, '2026-06-19 18:23:33.642238+05:30', '{worker_labourer}', '{}', 'any', '{}', 16, 59, NULL, false, 'any', false, false, NULL, NULL, '{social_welfare,employment}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('08fc5036-487c-4eb7-b2aa-684526a029cb', 'Craftsmen Training Scheme (CTS) — ITI', 'शिल्पकार प्रशिक्षण योजना (ITI)', '815d4c5c-61da-4c05-8f85-48ccb1bfee43', NULL, 'Provide NSQF-compliant long-duration vocational training across ~150 engineering and non-engineering trades through Industrial Training Institutes (ITIs), producing certified craftsmen/tradespeople for industry and self-employment.', 'औद्योगिक प्रशिक्षण संस्थाओं (ITI) के माध्यम से ~150 इंजीनियरिंग एवं गैर-इंजीनियरिंग ट्रेडों में NSQF-अनुरूप दीर्घकालिक व्यावसायिक प्रशिक्षण प्रदान कर उद्योग एवं स्वरोजगार के लिए प्रमाणित शिल्पकार/ट्रेड-कर्मी तैयार करना।', 'Youth seeking trade/craftsman skills; admission through ITIs with trade- and duration-specific entry requirements (generally Class 8 or Class 10 pass depending on trade); minimum age 14. Open to Bihar residents through government and private ITIs across the state.', 'कौशल/शिल्पकार प्रशिक्षण चाहने वाले युवा; ITI में ट्रेड एवं अवधि के अनुसार प्रवेश (सामान्यतः कक्षा 8 या 10 उत्तीर्ण, ट्रेड-अनुसार); न्यूनतम आयु 14 वर्ष। बिहार के सरकारी एवं निजी ITI के माध्यम से बिहार निवासियों हेतु।', 'training', 'Long-duration (6 months to 2 years) NSQF-compliant vocational training across ~150 engineering and non-engineering trades (including dedicated trades for women and PwDs), leading to a National Trade Certificate (NTC) recognised by industry and government. Training at government and private ITIs with workshops, tools and equipment provided.', 'Youth (14+) seeking trade/vocational certification', 'https://www.apprenticeshipindia.gov.in/', 'active', 'Fetched official Bihar Technical Education (det.bihar.gov.in/cts.html) page confirming CTS operates through the Bihar ITI network; MSDE/DGT national scheme with active admissions across ~15,000 ITIs nationwide including in Bihar. NTC certification is government-recognised.', NULL, NULL, 'https://det.bihar.gov.in/cts.html', '2026-06-22', NULL, '2026-06-22 13:06:26.932232+05:30', '{unemployed_youth,student}', '{secondary}', 'any', '{}', 14, NULL, NULL, false, 'any', false, false, NULL, NULL, '{skilling,employment,education}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('259f660a-4924-4bbb-b2c2-9827b0688750', 'Deen Dayal Upadhyaya Grameen Kaushalya Yojana (DDU-GKY) — Bihar', 'दीन दयाल उपाध्याय ग्रामीण कौशल्य योजना', 'da92c11b-dd4f-4018-a747-be904a71f544', NULL, 'Transform economically disadvantaged rural youth into self-reliant, market-relevant workers through placement-linked, market-driven skill training, with a focus on poor rural households.', 'स्थान-संबद्ध, बाजार-आधारित कौशल प्रशिक्षण के माध्यम से गरीब ग्रामीण युवाओं को आत्मनिर्भर, बाजार-प्रासंगिक कामगार बनाना।', 'Rural poor youth aged 15-35 (up to 45 for women, PVTGs, PwDs, transgender persons and special groups), identified as poor via Participatory Identification of Poor, BPL/SECC auto-inclusion, MGNREGA households, RSBY/Antyodaya cardholders or NRLM SHG membership. Mandatory coverage for SC/ST (34%), minorities (13%) and women (33%). Bihar-resident rural youth apply through JEEViKA/training partners.', '15–35 वर्ष (महिलाओं, PVTG, दिव्यांग, ट्रांसजेंडर हेतु 45 तक) के ग्रामीण गरीब युवा, जिनकी पहचान PIP/BPL/SECC/मनरेगा परिवार या NRLM SHG सदस्यता से होती है। SC/ST (34%), अल्पसंख्यक (13%), महिला (33%) अनिवार्य कवरेज। जीविका/प्रशिक्षण भागीदारों के माध्यम से आवेदन।', 'training', 'Free, fully residential or non-residential market-driven skill training with national/internationally aligned certification, mandatory placement support (target of at least 70-75% of trained candidates placed in jobs), post-placement support and migration/handholding assistance.', 'Rural poor youth (15–45)', 'https://kaushal.rural.gov.in/', 'active', 'BRLPS/JEEViKA official skills-and-jobs page details DDU-GKY as a currently-run program with placement targets and ongoing Expression of Interest for training partners in Bihar; central MoRD scheme remains active on the unified kaushal.rural.gov.in portal. JEEViKA is named as the standing nodal agency for Bihar.', NULL, NULL, 'https://brlps.in/skillsandjobs', '2026-06-22', NULL, '2026-06-22 12:27:36.779072+05:30', '{unemployed_youth,shg_jeevika_member}', '{}', 'any', '{}', 15, 45, NULL, false, 'any', false, false, NULL, NULL, '{skilling,employment,social_welfare}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('48581734-c1ed-476e-a7ac-969230027ef3', 'Kabir Antyeshti Anudan Yojana', 'कबीर अंत्येष्टि अनुदान योजना', 'b9da0199-24c5-4382-b284-74f9e43d390c', NULL, 'Immediate assistance to a poor family for the last rites of a deceased member.', 'किसी सदस्य की मृत्यु पर निर्धन परिवार को अंतिम संस्कार हेतु तत्काल सहायता।', 'BPL family in Bihar on the death of a member; applied via the local body / district welfare office.', 'किसी सदस्य की मृत्यु पर बिहार का BPL परिवार; स्थानीय निकाय / ज़िला कल्याण कार्यालय के माध्यम से।', 'Last-rites assistance', '₹3,000 immediate last-rites assistance for a BPL family, routed via the local body''s account on e-Suvidha.', 'BPL families of Bihar.', 'https://esuvidha.bihar.gov.in', 'active', 'Active — disbursed in FY2024-25 (e.g. Begusarai paid 3,030 cases at ₹3,000 each; Prabhat Khabar, Mar 2025); BPL family + 10-year Bihar residency. Verified 2026-06-19. Source: https://esuvidha.bihar.gov.in/', NULL, NULL, 'https://state.bihar.gov.in/socialwelfare', '2026-06-19', NULL, '2026-06-19 18:16:08.39734+05:30', '{}', '{}', 'any', '{}', NULL, NULL, NULL, true, 'bihar', false, false, NULL, NULL, '{social_welfare}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('96c95c3f-637f-40e1-8550-98033b16e155', 'JEEViKA (Bihar Rural Livelihoods) SHG Support', 'जीविका (बिहार ग्रामीण आजीविका) स्वयं सहायता समूह सहायता', '2c5ae0d5-a340-4379-bcf0-f008c2796f74', NULL, 'Organise rural poor women into Self-Help Groups with revolving funds, bank credit and livelihoods support.', 'ग्रामीण निर्धन महिलाओं को स्वयं सहायता समूहों में संगठित कर रिवॉल्विंग फंड, बैंक ऋण व आजीविका सहायता।', 'Rural women of Bihar who join a Jeevika SHG.', 'जीविका स्वयं सहायता समूह से जुड़ने वाली बिहार की ग्रामीण महिलाएँ।', 'Revolving fund + credit linkage', 'SHG support: one-time revolving fund + initial capitalisation / community investment fund grants, bank credit linkage, and capacity-building/training (amounts vary by stage).', 'Rural poor women (SHG members).', 'https://brlps.in', 'active', 'Active — BRLPS/JEEViKA official portal live; FY2024-25 Annual Action Plan & Budget published; also the delivery rail for the 2025 Mahila Rojgar Yojana. Verified 2026-06-19. Source: https://brlps.in/', NULL, NULL, 'https://brlps.in', '2026-06-19', NULL, '2026-06-19 17:38:29.840786+05:30', '{shg_jeevika_member}', '{}', 'female', '{}', NULL, NULL, NULL, false, 'bihar', false, false, NULL, NULL, '{women_child,financial_inclusion,employment}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('1d8a5673-acf9-40dc-99a2-f22ef717209b', 'Bihar Parivarik Labh Yojana', 'बिहार पारिवारिक लाभ योजना', '3df327f2-b1bf-440d-a46f-840341a10329', NULL, 'One-time lump-sum support to a BPL family on the death of its primary breadwinner.', 'मुख्य कमाने वाले की मृत्यु पर BPL परिवार को एकमुश्त सहायता।', 'BPL families of Bihar whose primary earner (aged 18–60) has died.', 'बिहार के BPL परिवार जिनके मुख्य कमाने वाले (आयु 18–60) की मृत्यु हुई हो।', 'Lump-sum assistance', 'Reported ₹20,000 one-time. Verify current amount.', 'BPL families of Bihar.', 'https://state.bihar.gov.in/socialwelfare', 'likely_active', 'Likely active — Bihar''s delivery of the National Family Benefit Scheme (₹20,000 one-time on a BPL breadwinner''s death, age 18–60), via serviceonline.bihar.gov.in; confirmed on NIC pages but no current-FY notification found. Verified 2026-06-19. Source: https://serviceonline.bihar.gov.in/', NULL, NULL, 'https://state.bihar.gov.in/socialwelfare', '2026-06-19', NULL, '2026-06-19 17:38:29.852126+05:30', '{}', '{}', 'any', '{}', NULL, NULL, NULL, true, 'bihar', false, false, NULL, NULL, '{social_welfare}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('f289689e-0b9f-4afd-9dd4-bbaae121261e', 'District Mineral Foundation Trust (DMFT) Schemes', 'ज़िला खनिज फाउंडेशन ट्रस्ट (DMFT) योजनाएँ', 'b9da0199-24c5-4382-b284-74f9e43d390c', NULL, 'District-level development works (health, education, drinking water, livelihoods) for communities in mining-affected areas, funded by mining royalties.', 'खनन-प्रभावित क्षेत्रों के समुदायों हेतु ज़िला-स्तरीय विकास कार्य (स्वास्थ्य, शिक्षा, पेयजल, आजीविका), खनन रॉयल्टी से वित्त-पोषित।', 'Communities/persons affected by mining in Bihar''s mining districts; works prioritised by the district DMFT.', 'बिहार के खनन ज़िलों में खनन-प्रभावित समुदाय/व्यक्ति; कार्य ज़िला DMFT द्वारा प्राथमिकता अनुसार।', 'District development works', 'Funds health, education, water and livelihood works in mining-affected areas (per district DMFT plans).', 'Mining-affected communities (relevant districts).', 'https://state.bihar.gov.in/mines', 'active', 'Active — DMFs operate across Bihar''s mining districts under PMKKKY (revamped Jan 2024); National DMF Summit Mar 2026; live Bihar PMKKKY dashboard. Funds health/education/water/livelihood works in mining-affected areas. Verified 2026-06-19. Source: https://mitra.ibm.gov.in/pmkkky/Bihar/Pages/Dashboard.aspx', NULL, NULL, 'https://state.bihar.gov.in/mines', '2026-06-19', NULL, '2026-06-19 18:16:08.401764+05:30', '{}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'bihar', false, false, NULL, NULL, '{social_welfare,health,education}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('e07a2763-0cec-4609-bb98-e7268342770b', 'Jananayak Karpoori Thakur Kisan Samman Nidhi', 'जननायक कर्पूरी ठाकुर किसान सम्मान निधि', '77fa7e43-0589-4b9b-8807-bbafc0146d67', NULL, 'State income support to farmers (over and above central PM-Kisan).', 'किसानों को राज्य आय-सहायता (केंद्रीय पीएम-किसान के अतिरिक्त)।', 'Eligible farmer families of Bihar registered on the Agriculture DBT portal.', 'कृषि DBT पोर्टल पर पंजीकृत बिहार के पात्र किसान परिवार।', 'Income support (DBT)', '₹3,000/year Bihar state top-up to farmer income support (₹9,000/year combined with the central PM-KISAN ₹6,000).', 'Farmer families of Bihar.', 'https://dbtagriculture.bihar.gov.in', 'likely_active', 'Likely active — newly announced in Bihar''s 2026-27 budget (Feb 2026) as a ₹3,000/year state top-up over PM-KISAN (PRS); rollout pending, so not yet ''active''. [Corrected: ₹9,000 is the combined figure, not a ₹9,000 state benefit.] Verified 2026-06-19. Source: https://prsindia.org/budgets/states/bihar-budget-analysis-2026-27', NULL, NULL, 'https://dbtagriculture.bihar.gov.in', '2026-06-19', NULL, '2026-06-19 17:38:29.847504+05:30', '{farmer}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'bihar', false, false, 'any', NULL, '{agriculture}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('9d517d5e-f86d-4c40-b752-596065a3efe4', 'Janani Shishu Suraksha Karyakram (JSSK)', 'जननी शिशु सुरक्षा कार्यक्रम', 'f99905da-40dd-4df9-93cc-4c6acb3516e1', '2011-06-01', 'Eliminate out-of-pocket expenses for pregnant women delivering in public health institutions and for treatment of sick newborns and infants, thereby promoting institutional delivery and infant survival.', 'सार्वजनिक स्वास्थ्य संस्थानों में प्रसव कराने वाली गर्भवती महिलाओं तथा बीमार नवजात/शिशुओं के उपचार में जेब-खर्च समाप्त करना।', 'All pregnant women delivering in public health institutions, and all sick newborns/infants up to one year of age accessing public health institutions. No application or income test — entitlements are automatic at government facilities.', 'सार्वजनिक स्वास्थ्य संस्थानों में प्रसव कराने वाली सभी गर्भवती महिलाएँ, तथा एक वर्ष तक के सभी बीमार नवजात/शिशु। कोई आवेदन या आय-परीक्षण नहीं — सरकारी सुविधाओं में स्वतः लाभ।', 'free service', 'Entirely free, zero-expense services at public health institutions: free delivery including caesarean section; free drugs and consumables; free diagnostics; free blood when required; free diet (3 days for normal delivery, 7 days for C-section); and free transport (home-to-institution, inter-facility referral, and drop-back). Same free entitlements extended to sick newborns and infants up to one year of age.', 'Pregnant women & sick infants', NULL, 'active', 'Fetched the NHM/MoHFW JSSK page (nhm.gov.in, level=3 sublinkid=842), which describes JSSK as launched 1 June 2011, extended in 2014, and currently entitling all pregnant women and sick infants to free services in public facilities — an ongoing NHM program operating across all states including Bihar.', NULL, NULL, 'https://nhm.gov.in/index1.php?lang=1&level=3&sublinkid=842&lid=308', '2026-06-22', NULL, '2026-06-22 12:27:36.779072+05:30', '{pregnant_lactating_woman}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'any', false, false, NULL, NULL, '{health,women_child}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('9b5b0ebe-94c6-455d-95e3-cb8ba5e18996', 'Laxmibai Social Security (Widow) Pension Yojana', 'लक्ष्मीबाई सामाजिक सुरक्षा (विधवा) पेंशन योजना', '3df327f2-b1bf-440d-a46f-840341a10329', NULL, 'Monthly social-security pension for widows in Bihar.', 'बिहार की विधवाओं हेतु मासिक सामाजिक-सुरक्षा पेंशन।', 'Widow, permanent resident of Bihar, typically aged 18+, from a BPL/eligible family (verify criteria at SSPMIS).', 'विधवा, बिहार की स्थायी निवासी, सामान्यतः 18+ आयु, BPL/पात्र परिवार से (मानदंड SSPMIS पर सत्यापित करें)।', 'Monthly pension (DBT)', '₹1,100 per month (raised from ₹400 in July 2025), paid by DBT via SSPMIS.', 'Widows of Bihar.', 'https://www.sspmis.bihar.gov.in', 'active', 'Active — among the six social-security pensions raised to a flat ₹1,100/month effective July 2025 (was ₹400). For widows aged 18+ with annual family income below ₹60,000 (Bihar resident), via SSPMIS. Verified 2026-06-19. Source: https://www.sspmis.bihar.gov.in/', NULL, NULL, 'https://www.sspmis.bihar.gov.in', '2026-06-19', NULL, '2026-06-19 17:50:07.601296+05:30', '{widow}', '{}', 'female', '{}', 18, NULL, 60000, false, 'bihar', false, false, NULL, NULL, '{social_welfare,women_child}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('cbc66449-1bb9-4421-af07-c7d63a9f9f23', 'MGNREGA (Bihar)', 'मनरेगा (बिहार)', '2c5ae0d5-a340-4379-bcf0-f008c2796f74', NULL, 'Guaranteed wage employment for rural households willing to do unskilled manual work.', 'अकुशल शारीरिक कार्य हेतु इच्छुक ग्रामीण परिवारों को गारंटीशुदा मज़दूरी रोज़गार।', 'Adult members of rural households in Bihar with a job card.', 'जॉब कार्ड धारक बिहार के ग्रामीण परिवारों के वयस्क सदस्य।', 'Guaranteed wage employment', 'Up to 100 days of guaranteed work per household per year at the notified daily wage. Verify the current wage rate.', 'Rural households of Bihar.', 'https://nrega.nic.in', 'active', 'Active — scheme budget line confirmed two years running: ₹4,392 cr (2025-26 BE) and ₹3,192 cr (2026-27 BE), from the Bihar Budget Documents as itemised by PRS Legislative Research. A current-fiscal-year allocation is present. Verified 2026-06-19.', '2026-27', NULL, 'https://nrega.nic.in', '2026-06-19', NULL, '2026-06-19 17:38:29.846589+05:30', '{worker_labourer}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'bihar', false, false, NULL, NULL, '{employment,social_welfare}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('ab7d17ba-39bd-4c27-a485-d8f1c2ca2dd1', 'Kushal Yuva Program (KYP)', 'कुशल युवा कार्यक्रम', 'b4cdf34b-599a-4ee4-9d31-cecac8488797', NULL, 'Employability training for youth in Bihar — Hindi & English communication, basic computer skills, and soft/behavioural skills.', 'बिहार के युवाओं हेतु रोज़गार-योग्यता प्रशिक्षण — हिंदी व अंग्रेज़ी संवाद, बुनियादी कंप्यूटर कौशल, एवं सॉफ्ट/व्यवहार कौशल।', 'Youth in Bihar who have passed at least class 10 and are not in formal education. Note: sources differ on the upper age limit (15–25 vs 15–28) — confirm against the KYP guideline (rev. 22/02/2017).', 'बिहार के युवा जिन्होंने कम से कम 10वीं उत्तीर्ण की हो और औपचारिक शिक्षा में न हों। नोट: ऊपरी आयु-सीमा पर स्रोतों में भिन्नता (15–25 बनाम 15–28) — KYP दिशानिर्देश (संशोधन 22/02/2017) से पुष्टि करें।', 'Skill training', 'Approximately 240 hours of training covering language & communication, basic computer skills, and soft skills. Completion is mandatory for MNSSBY allowance beneficiaries.', 'Youth in Bihar (class 10 passed, not in formal education) seeking employability skills.', 'https://www.7nishchay-yuvaupmission.bihar.gov.in/', 'active', 'Active — official 7nishchay portal lists KYP live under the Bihar Skill Development Mission (240-hour training: communication, basic computer, soft skills; free). Eligibility 15–28 (relaxations: SC/ST & PwD to 33, OBC to 31), 10th-pass. Verified 2026-06-19. Source: https://www.7nishchay-yuvaupmission.bihar.gov.in/', NULL, NULL, 'https://www.7nishchay-yuvaupmission.bihar.gov.in/', '2026-06-19', NULL, '2026-06-18 19:41:39.101502+05:30', '{unemployed_youth}', '{secondary}', 'any', '{}', 15, 28, NULL, false, 'bihar', false, false, NULL, NULL, '{skilling,employment}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('4c771dad-dc5c-43ff-a706-b626af6897ea', 'Mukhyamantri Balak/Balika Cycle Yojana', 'मुख्यमंत्री बालक/बालिका साइकिल योजना', 'c6f71956-defd-4037-8324-6c3e805899ba', NULL, 'A grant to Class 9 students in government secondary schools to buy a bicycle, reducing distance-related dropout.', 'सरकारी माध्यमिक विद्यालयों के कक्षा 9 के विद्यार्थियों को साइकिल खरीदने हेतु अनुदान, ताकि दूरी के कारण होने वाले ड्रॉपआउट को कम किया जा सके।', 'Students (girls and boys) enrolled in Class 9 in a Bihar government secondary school.', 'बिहार के सरकारी माध्यमिक विद्यालय में कक्षा 9 में नामांकित विद्यार्थी (बालक एवं बालिका)।', 'Cash grant (DBT)', '₹3,000 transferred to the student''s account to purchase a bicycle.', 'Class 9 students in Bihar government schools.', 'https://medhasoft.bihar.gov.in', 'likely_active', 'Likely active — reported running via medhasoft (₹3,000 to Class-9 students for a bicycle; often bundled with the uniform/Poshak grant). First-party medhasoft notification not captured, so not upgraded to active. Verified 2026-06-19. Source: https://medhasoft.bihar.gov.in/', NULL, NULL, 'https://medhasoft.bihar.gov.in', '2026-06-19', NULL, '2026-06-19 14:20:00.939785+05:30', '{student}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'bihar', false, false, NULL, NULL, '{education}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('8c1f5b49-2fb6-4a34-ab52-0bfb2e639618', 'Mukhyamantri Divyangjan Pension Yojana', 'मुख्यमंत्री दिव्यांगजन पेंशन योजना', '3df327f2-b1bf-440d-a46f-840341a10329', NULL, 'Monthly social-security pension for persons with disabilities resident in Bihar.', 'बिहार में निवासरत दिव्यांगजनों हेतु मासिक सामाजिक-सुरक्षा पेंशन।', 'Permanent resident of Bihar who is a person with disability (a disability certificate is typically required), not a retired government employee and not receiving any other government/social-security pension. Confirm the minimum disability percentage at the source.', 'बिहार का स्थायी निवासी दिव्यांगजन (सामान्यतः दिव्यांगता प्रमाण-पत्र आवश्यक), जो सेवानिवृत्त सरकारी कर्मचारी न हो एवं किसी अन्य सरकारी/सामाजिक-सुरक्षा पेंशन का लाभार्थी न हो। न्यूनतम दिव्यांगता प्रतिशत स्रोत से सत्यापित करें।', 'Monthly pension (DBT)', '₹1,100 per month (raised from ₹400 in July 2025). Paid via Direct Benefit Transfer.', 'Persons with disabilities in Bihar.', 'https://www.sspmis.bihar.gov.in', 'active', 'Active — disability pension raised to ₹1,100/month effective July 2025 (was ₹400), paid by DBT. Eligibility: 40%+ disability, via SSPMIS / Lok Seva. Verified 2026-06-19. Source: https://www.sspmis.bihar.gov.in/', NULL, NULL, 'https://www.sspmis.bihar.gov.in', '2026-06-19', NULL, '2026-06-19 14:20:00.938081+05:30', '{}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'bihar', true, false, NULL, NULL, '{social_welfare}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('69d8804c-688c-4ac5-8f74-cb6c650dbd62', 'Mukhyamantri Kanya Utthan Yojana', 'मुख्यमंत्री कन्या उत्थान योजना', 'c6f71956-defd-4037-8324-6c3e805899ba', '2018-04-25', 'Financial incentives to girls in Bihar from birth through graduation, to improve girls'' education and well-being.', 'लड़कियों की शिक्षा एवं कल्याण हेतु जन्म से स्नातक तक बिहार की बेटियों को वित्तीय प्रोत्साहन।', 'Girl students who are permanent residents of Bihar. No income limit — open to all categories. Benefits are paid at stages (e.g. on passing intermediate and on graduation); the account must be in the girl''s name and Aadhaar-linked.', 'बिहार की स्थायी निवासी छात्राएँ। कोई आय-सीमा नहीं — सभी श्रेणियों हेतु। लाभ चरणों में (जैसे इंटरमीडिएट एवं स्नातक उत्तीर्ण करने पर) देय; खाता बालिका के नाम एवं आधार से जुड़ा हो।', 'Cash incentive (DBT)', 'Graduation incentive ₹50,000 (one-time); intermediate incentive ₹25,000 (first division) or ₹15,000 (second division). Paid by DBT to the Aadhaar-linked account.', 'Girls / women students of Bihar.', 'https://medhasoft.bihar.gov.in', 'active', 'Active — medhasoft portal shows ''2026 Registration Open'' for the intermediate and graduation components. Graduation ₹50,000 (one-time, DBT); intermediate ₹25,000 (first division) / ₹15,000 (second division); unmarried at the intermediate stage. Verified 2026-06-19. Source: https://medhasoft.bihar.gov.in/', NULL, NULL, 'https://medhasoft.bihar.gov.in', '2026-06-19', NULL, '2026-06-19 14:17:34.322088+05:30', '{student}', '{}', 'female', '{}', NULL, NULL, NULL, false, 'bihar', false, false, NULL, NULL, '{education,women_child}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('aa2f34d7-ed26-4e47-ba96-18505ac2d057', 'Mukhyamantri Kanya Vivah Yojana', 'मुख्यमंत्री कन्या विवाह योजना', '3df327f2-b1bf-440d-a46f-840341a10329', NULL, 'Financial assistance to economically weaker families for a daughter''s marriage, and to promote marriage registration.', 'आर्थिक रूप से कमज़ोर परिवारों को बेटी के विवाह हेतु वित्तीय सहायता एवं विवाह पंजीकरण को बढ़ावा।', 'Bride must be a resident of Bihar, at least 18 (groom at least 21), from a family with annual income up to ₹60,000. The marriage must be legally registered (and solemnised after 22 Nov 2007).', 'वधू बिहार निवासी, आयु कम से कम 18 (वर कम से कम 21), परिवार की वार्षिक आय ₹60,000 तक। विवाह विधिवत पंजीकृत हो (एवं 22 नवम्बर 2007 के बाद संपन्न)।', 'Cash assistance (DBT)', 'One-time ₹5,000 to the bride (by DBT) on a registered marriage where the bride is 18+ (BPL family).', 'Daughters of economically weaker families in Bihar.', 'https://serviceonline.bihar.gov.in', 'active', 'Active — a live statutory RTPS service on serviceonline.bihar.gov.in (21-day timeline). [Corrected: ₹5,000 one-time, not ₹5,000–₹10,000; paid to the bride by DBT.] Verified 2026-06-19. Source: https://serviceonline.bihar.gov.in/', NULL, NULL, 'https://serviceonline.bihar.gov.in', '2026-06-19', NULL, '2026-06-19 14:20:00.935037+05:30', '{}', '{}', 'female', '{}', 18, NULL, 60000, false, 'bihar', false, false, NULL, NULL, '{social_welfare,women_child}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('53559c00-2ba9-4a3c-b7aa-fcce7dd715db', 'Mukhyamantri Mahila Rojgar Yojana', 'मुख्यमंत्री महिला रोज़गार योजना', '656e1179-0bc5-45c0-b0b2-da0acbce5907', NULL, 'Stipend, micro-enterprise support and skilling for women to start livelihoods.', 'महिलाओं को आजीविका शुरू करने हेतु भत्ता, सूक्ष्म-उद्यम सहायता एवं कौशल।', 'Women of Bihar (priority to SHG/Jeevika members); details to verify at source.', 'बिहार की महिलाएँ (स्वयं सहायता समूह/जीविका सदस्यों को प्राथमिकता); विवरण स्रोत से सत्यापित करें।', 'Stipend + enterprise support', 'One-time ₹10,000 startup grant per woman (DBT), plus an optional top-up of up to ₹2 lakh for ventures showing progress after ~6 months. Delivered via the JEEViKA / SHG network.', 'Women of Bihar.', 'https://brlps.in', 'active', 'Active — launched 26 Sept 2025 (₹7,500 cr scheme): a ONE-TIME ₹10,000 grant per woman by DBT, with an optional second-stage top-up up to ₹2 lakh for viable ventures after ~6 months. Delivered through JEEViKA / urban SHGs (Rural Development Dept); 1.1+ crore women selected (₹10,000 to 21 lakh more on 6 Oct 2025). [Corrected: was stored as a ₹10,000/month stipend — it is a one-time grant.] Verified 2026-06-19. Source: https://www.pmindia.gov.in/en/news_updates/pm-launches-bihars-mukhyamantri-mahila-rojgar-yojana/', NULL, NULL, 'https://industries.bihar.gov.in', '2026-06-19', NULL, '2026-06-19 17:38:29.838795+05:30', '{self_employed_entrepreneur,shg_jeevika_member}', '{}', 'female', '{}', NULL, NULL, NULL, false, 'bihar', false, false, NULL, NULL, '{employment,women_child,financial_inclusion}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('58d7c82a-549a-4a99-8834-09effa93eba8', 'Mukhyamantri Medhavriti Yojana', 'मुख्यमंत्री मेधावृत्ति योजना', '3df327f2-b1bf-440d-a46f-840341a10329', NULL, 'Merit incentive for SC/ST girl students who pass Class 12.', '12वीं उत्तीर्ण करने वाली SC/ST छात्राओं हेतु मेधा प्रोत्साहन।', 'SC/ST girls of Bihar passing Class 12 from a recognised board.', 'मान्यता प्राप्त बोर्ड से 12वीं उत्तीर्ण बिहार की SC/ST छात्राएँ।', 'Cash incentive', 'Reported ₹15,000 (1st division) / ₹10,000 (2nd division). Verify at the portal.', 'SC/ST girl students of Bihar.', 'https://www.medhasoft.bihar.gov.in', 'likely_active', 'Likely active — merit scholarship reported running via medhasoft for 2025: ₹15,000 (first division) / ₹10,000 (second division) for SC/ST & minority intermediate-pass students, with a separate BC/EBC variant run by the BC/EBC Welfare Department. [Corrected: it is an intermediate-pass, not matric, incentive.] Verified 2026-06-19. Source: https://medhasoft.bihar.gov.in/', NULL, NULL, 'https://www.medhasoft.bihar.gov.in', '2026-06-19', NULL, '2026-06-19 17:38:29.831529+05:30', '{student}', '{senior_secondary}', 'female', '{sc,st}', NULL, NULL, NULL, false, 'bihar', false, false, NULL, NULL, '{education,women_child}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('b7b2c47e-f98b-41de-b7c5-a676be7727db', 'Mukhyamantri Nishchay Swayam Sahayata Bhatta (MNSSBY)', 'मुख्यमंत्री निश्चय स्वयं सहायता भत्ता योजना', 'b4cdf34b-599a-4ee4-9d31-cecac8488797', '2016-10-02', 'Financial support to unemployed youth of Bihar while they search for employment.', 'रोज़गार की तलाश के दौरान बिहार के बेरोज़गार युवाओं को वित्तीय सहायता।', 'Permanent resident of Bihar aged 20–25, unemployed and actively seeking work, who has passed class 12 but is not enrolled in higher education. Enrolment in Kushal Yuva Program training is mandatory.', 'बिहार का स्थायी निवासी, आयु 20–25 वर्ष, बेरोज़गार एवं रोज़गार की तलाश में, जिसने 12वीं उत्तीर्ण की हो परन्तु उच्च शिक्षा में नामांकित न हो। कुशल युवा कार्यक्रम प्रशिक्षण में नामांकन अनिवार्य।', 'Monthly cash allowance', '₹1,000 per month for a maximum period of two years.', 'Unemployed youth of Bihar aged 20–25 searching for employment.', 'https://www.7nishchay-yuvaupmission.bihar.gov.in/', 'active', 'Active — official 7nishchay portal lists it live and accepting registrations (also on UMANG). ₹1,000/month for up to 2 years for unemployed Bihar youth aged 20–25 (12th-passed, not in higher studies). Verified 2026-06-19. Source: https://www.7nishchay-yuvaupmission.bihar.gov.in/', NULL, NULL, 'https://www.7nishchay-yuvaupmission.bihar.gov.in/', '2026-06-19', NULL, '2026-06-18 19:41:39.100417+05:30', '{unemployed_youth}', '{senior_secondary}', 'any', '{}', 20, 25, NULL, false, 'bihar', false, false, NULL, NULL, '{employment}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('c5bf6e25-04a6-45fa-99c3-331b55a711e2', 'Mukhyamantri Pratigya Yojana (Internship)', 'मुख्यमंत्री प्रतिज्ञा योजना (इंटर्नशिप)', '896891da-f714-41d6-b6bb-fd84e5ecfb00', NULL, 'Internship/stipend scheme to give unemployed youth work experience.', 'बेरोज़गार युवाओं को कार्य-अनुभव देने हेतु इंटर्नशिप/भत्ता योजना।', 'Unemployed youth of Bihar aged 18–28 (educational criteria apply; verify at source).', 'बिहार के बेरोज़गार युवा, आयु 18–28 (शैक्षिक मानदंड लागू; स्रोत से सत्यापित करें)।', 'Internship stipend', 'Internship stipend of ₹4,000 (12th) / ₹5,000 (ITI or diploma) / ₹6,000 (graduate and above) per month, plus ₹2,000 if interning outside the home district or ₹5,000 if outside Bihar.', 'Unemployed youth of Bihar.', 'https://cmpratigya.bihar.gov.in/', 'likely_active', 'Likely active — approved by the Bihar cabinet on 1 Jul 2025 under Saat Nishchay-2 with an official portal (cmpratigya.bihar.gov.in); employer registration opened, candidate registration rolling out. Verified 2026-06-19. Source: https://cmpratigya.bihar.gov.in/', NULL, NULL, 'https://state.bihar.gov.in/labour', '2026-06-19', NULL, '2026-06-19 17:38:29.843179+05:30', '{unemployed_youth}', '{senior_secondary}', 'any', '{}', 18, 28, NULL, false, 'bihar', false, false, NULL, NULL, '{employment,skilling}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('3d32a267-8ced-425b-a6c3-54d34d2db7e2', 'Mukhyamantri Shram Shakti Yojana', 'मुख्यमंत्री श्रमशक्ति योजना', '96c5eea2-fbd9-4785-b5c9-af40dbd5be5d', NULL, 'Provide employment-oriented vocational skill training to men and women of minority communities in Bihar so they can secure jobs or move toward self-employment, with self-employment loans available separately via the linked Mukhyamantri Alpsankhyak Rozgar Rin Yojana.', 'बिहार के अल्पसंख्यक समुदायों के स्त्री-पुरुषों को रोजगारोन्मुख व्यावसायिक कौशल प्रशिक्षण देना ताकि वे नौकरी या स्वरोजगार की ओर बढ़ सकें।', 'Permanent residents of Bihar belonging to notified minority communities, aged 18-45, with annual family income below Rs 4,50,000; minimum education typically 8th/10th pass depending on the course. 30% reservation for women and 3% for persons with disabilities. Apply online via the BSMFC portal.', 'अधिसूचित अल्पसंख्यक समुदायों के बिहार के स्थायी निवासी, आयु 18–45, वार्षिक पारिवारिक आय 4,50,000 रु. से कम; पाठ्यक्रम अनुसार न्यूनतम शिक्षा प्रायः 8वीं/10वीं। महिलाओं हेतु 30% एवं दिव्यांगों हेतु 3% आरक्षण।', 'training', 'Free job-oriented vocational skill training (training period up to 2 years) through empanelled government and private training providers, with study materials and tool-kits provided free of cost, and a certificate awarded on successful completion by the training institute.', 'Minority youth (18–45, income < ₹4.5L)', 'https://bsmfc.org/', 'likely_active', 'BSMFC official scheme page describes a live ''Apply for Skill Training'' online portal and lists training-provider documentation; district administrations (e.g., Madhubani NIC) have issued recent online-application invitation notices for minority candidates under the scheme. No current-FY state budget line was confirmed from budget.bihar.gov.in, so status is likely_active rather than active. Distinct from the loan-only ''Bihar Alpsankhyak Rozgar Rin'' already in catalogue.', NULL, NULL, 'https://bsmfc.org/schemes/mukhyamantrishram-shakti-yojna/', '2026-06-22', NULL, '2026-06-22 12:27:36.779072+05:30', '{unemployed_youth}', '{}', 'any', '{minority}', 18, 45, 450000, false, 'bihar', false, false, NULL, NULL, '{skilling,employment,social_welfare}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('51b61534-376b-48de-a2d7-dc2ddec79260', 'Mukhyamantri Udyami Yojana', 'मुख्यमंत्री उद्यमी योजना', '656e1179-0bc5-45c0-b0b2-da0acbce5907', NULL, 'Promote first-generation entrepreneurship in Bihar by financing new micro/small enterprises.', 'नए सूक्ष्म/लघु उद्यमों हेतु वित्त प्रदान कर बिहार में प्रथम-पीढ़ी उद्यमिता को बढ़ावा देना।', 'Permanent resident of Bihar aged 18–45, with at least class 12 / ITI / Diploma / Graduate (per component). Components for SC/ST, EBC, BC, Women and Youth. SC/ST/EBC/women loans are interest-free; general youth pay 1% simple interest.', 'बिहार का स्थायी निवासी, आयु 18–45, न्यूनतम 12वीं / आईटीआई / डिप्लोमा / स्नातक (घटक अनुसार)। SC/ST, EBC, BC, महिला एवं युवा हेतु घटक। SC/ST/EBC/महिला ऋण ब्याज-मुक्त; सामान्य युवा 1% साधारण ब्याज।', 'Loan + subsidy', 'Up to ₹10 lakh — 50% subsidy (grant, up to ₹5 lakh) + 50% loan (up to ₹5 lakh) repayable over 84 months; the Youth category pays 1% interest. No collateral.', 'Aspiring entrepreneurs in Bihar (SC/ST/EBC/BC/women/youth).', 'https://udyami.bihar.gov.in', 'active', 'Active — official udyami.bihar.gov.in shows the FY2025-26 cycle (applications closed 23 Mar 2026, selection by randomisation 20 May 2026, document upload by 24 Jun 2026) — mid-cycle and operational. Categories: SC/ST, EBC, women, youth, minority; age 18–50; min education 10+2/ITI/diploma. Verified 2026-06-19. Source: https://udyami.bihar.gov.in/', NULL, NULL, 'https://udyami.bihar.gov.in', '2026-06-19', NULL, '2026-06-19 14:17:34.331182+05:30', '{self_employed_entrepreneur}', '{senior_secondary}', 'any', '{}', 18, 50, NULL, false, 'bihar', false, false, NULL, NULL, '{industry,financial_inclusion}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('f95d5d04-ca53-49ca-95b4-634869c5ea30', 'Mukhyamantri Vas Sthal Kray Sahayata Yojana', 'मुख्यमंत्री वास स्थल क्रय सहायता योजना', '2c5ae0d5-a340-4379-bcf0-f008c2796f74', NULL, 'Help landless and houseless rural families who are listed as PMAY-G beneficiaries but have no homestead land to first acquire residential land, so they can subsequently avail house-construction assistance under PMAY-G.', 'ऐसे ग्रामीण परिवारों की सहायता करना जो PMAY-ग्रामीण के लाभार्थी हैं किन्तु भूमिहीन हैं, ताकि वे आवासीय भूखंड क्रय कर सकें और फिर मकान-निर्माण सहायता प्राप्त कर सकें।', 'Rural Bihar resident; listed as a beneficiary under PMAY-Gramin; landless and houseless (owns no residential land/house); resides in a village where no government land is available for housing allocation; must have an operational bank account for DBT.', 'ग्रामीण बिहार निवासी; PMAY-ग्रामीण के लाभार्थी सूची में नाम; भूमिहीन एवं बेघर (कोई आवासीय भूमि/मकान नहीं); ऐसे गाँव में रहते हों जहाँ सरकारी भूमि उपलब्ध नहीं; DBT हेतु बैंक खाता आवश्यक।', 'cash transfer', 'Cash assistance of Rs. 60,000 transferred directly (DBT) to the beneficiary''s bank account, to be used exclusively for purchasing residential/homestead land. (Note: some 2025 sources report the amount revised upward to Rs. 1 lakh — re-verify against a Rural Development Department notification.)', 'Landless PMAY-G beneficiaries (rural Bihar)', NULL, 'likely_active', 'Listed as a live scheme on the Government of India myScheme portal (myscheme.gov.in/schemes/mmvsksy, Rural Development Dept, Bihar) and widely referenced in 2025 state sources as currently open. No current-FY Bihar Rural Development budget allocation confirmed — classed likely_active. Benefit amount discrepancy (Rs. 60,000 on myScheme vs Rs. 1 lakh in some 2025 news) flagged for re-verification against an RD notification. Distinct from Bihar Vaas Bhoomi Yojana (Revenue & Land Reforms free land grant — different dept and mechanism).', NULL, NULL, 'https://www.myscheme.gov.in/schemes/mmvsksy', '2026-06-22', NULL, '2026-06-22 13:06:26.932232+05:30', '{}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'bihar', false, false, NULL, NULL, '{housing,social_welfare}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('391ae50e-3613-426d-b5f4-87384cded4ca', 'Mukhyamantri Vridhjan Pension Yojana', 'मुख्यमंत्री वृद्धजन पेंशन योजना', '3df327f2-b1bf-440d-a46f-840341a10329', NULL, 'Monthly social-security pension for elderly residents of Bihar.', 'बिहार के वृद्ध निवासियों हेतु मासिक सामाजिक-सुरक्षा पेंशन।', 'Permanent resident of Bihar aged 60 or above, not a retired government employee and not receiving any other government/family/social-security pension.', 'बिहार का स्थायी निवासी, आयु 60 वर्ष या अधिक, जो सेवानिवृत्त सरकारी कर्मचारी न हो एवं किसी अन्य सरकारी/पारिवारिक/सामाजिक-सुरक्षा पेंशन का लाभार्थी न हो।', 'Monthly pension (DBT)', '₹1,100 per month (raised from ₹400/₹500 in July 2025), paid by DBT on the 10th of each month.', 'Senior citizens (60+) of Bihar.', 'https://www.sspmis.bihar.gov.in', 'active', 'Active — Bihar budget line ₹828 cr (2025-26 BE) under Social Welfare (Bihar Budget Documents, PRS analysis). Pension raised from ₹400/₹500 to a flat ₹1,100/month effective July 2025 (~1.09 crore beneficiaries, paid on the 10th by DBT). Verified 2026-06-19. Source: https://www.sspmis.bihar.gov.in/', '2025-26', NULL, 'https://www.sspmis.bihar.gov.in', '2026-06-19', NULL, '2026-06-19 14:17:34.333568+05:30', '{senior_citizen}', '{}', 'any', '{}', 60, NULL, NULL, false, 'bihar', false, false, NULL, NULL, '{social_welfare}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('956aeb53-5783-4299-8e34-1fecd9dd0154', 'National Apprenticeship Promotion Scheme (NAPS)', 'राष्ट्रीय शिक्षुता प्रोत्साहन योजना', 'c66b321c-bdc9-4ec8-ac24-ebc2520b937f', NULL, 'Promote apprenticeship training across the country by incentivising employers to engage apprentices, thereby giving youth (including ITI pass-outs, school pass-outs and skill-certificate holders) industry-based, paid, on-the-job skilling.', 'नियोक्ताओं को शिक्षुओं को रखने हेतु प्रोत्साहित कर शिक्षुता को बढ़ावा देना, जिससे युवाओं (ITI उत्तीर्ण, स्कूल उत्तीर्ण, कौशल-प्रमाणपत्रधारक) को सवेतन, उद्योग-आधारित ऑन-द-जॉब कौशल मिले।', 'Indian citizens aged 14+ (18+ for hazardous trades) with minimum 5th-class education; ITI pass-outs, Class 8/10/12 pass candidates, diploma holders, graduates and skill-certificate holders are eligible depending on trade. Open to Bihar youth; engagement is through registered employers/establishments on the apprenticeship portal.', '14 वर्ष से अधिक (खतरनाक व्यवसायों हेतु 18+) के भारतीय नागरिक, न्यूनतम 5वीं पास; ट्रेड के अनुसार ITI उत्तीर्ण, कक्षा 8/10/12, डिप्लोमा, स्नातक एवं कौशल-प्रमाणपत्रधारक पात्र। पोर्टल पर पंजीकृत नियोक्ताओं के माध्यम से बिहार के युवाओं हेतु खुला।', 'training', 'Apprentices receive a prescribed monthly stipend (revised in May 2025 to a range of approx. Rs 6,800-Rs 12,300/month), of which the Government contributes 25% of the prescribed minimum stipend up to Rs 1,500/month directly via DBT; for non-ITI candidates the Government also shares basic training cost up to Rs 7,500 for 500 hours/3 months. Apprentices gain certified, industry-recognised work experience.', 'Apprentices (youth 14+)', 'https://www.apprenticeshipindia.gov.in/', 'active', 'MSDE NAPS implementation guidelines (2024) and the May 2025 38th Central Apprenticeship Council decision revising stipends by 36% confirm the scheme is current and actively funded for 2025-26; quarterly reimbursement to employers is ongoing via RDATs/State Apprenticeship Advisors. Central scheme operated through apprenticeshipindia.gov.in.', NULL, NULL, 'https://www.apprenticeshipindia.gov.in/', '2026-06-22', NULL, '2026-06-22 12:27:36.779072+05:30', '{unemployed_youth}', '{}', 'any', '{}', 14, NULL, NULL, false, 'any', false, false, NULL, NULL, '{skilling,employment}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('cc974040-f5d9-4313-ae8f-17a74251ddf3', 'National Apprenticeship Training Scheme (NATS)', 'राष्ट्रीय शिक्षुता प्रशिक्षण योजना', 'b33f6690-fc00-4381-86cf-48c022f883bd', NULL, 'Provide fresh graduate, diploma and vocational-certificate holders with practical, on-the-job apprenticeship training (6 months to 1 year) under the Apprentices Act 1961, bridging the gap between classroom education and industry requirements.', 'नए स्नातक, डिप्लोमा एवं व्यावसायिक-प्रमाणपत्रधारकों को शिक्षुता अधिनियम 1961 के अंतर्गत 6 माह से 1 वर्ष तक का व्यावहारिक ऑन-द-जॉब शिक्षुता प्रशिक्षण देना।', 'Graduate students, diploma holders and vocational certificate holders (engineering, technical, and now commerce/arts/humanities streams) seeking apprenticeship training; registration on the NATS 2.0 portal. No income or social-category bar; open to recent graduates including those in Bihar.', 'शिक्षुता प्रशिक्षण चाहने वाले स्नातक, डिप्लोमा एवं व्यावसायिक-प्रमाणपत्रधारक; NATS 2.0 पोर्टल पर पंजीकरण। कोई आय या सामाजिक-श्रेणी बंधन नहीं; बिहार सहित नए स्नातकों के लिए खुला।', 'training', 'Hands-on apprenticeship training in an industry/establishment for 6 months to 1 year, a monthly stipend (aligned to minimum rates under the Apprentices Act; 50% of the stipend is reimbursed to the employer by the Government of India via DBT), and a Government of India Certificate of Proficiency registrable at employment exchanges as valid work experience. Widely promoted in Bihar as a ~Rs 9,000/month opportunity for recent graduates.', 'Graduate & diploma apprentices', 'https://nats.education.gov.in', 'active', 'Official NATS about-us page (Ministry of Education) confirms NATS 2.0 portal is operational with active establishments and stipend disbursal via DBT; PIB recorded launch of NATS 2.0 and disbursal of Rs 100 Cr stipends to graduates/diploma holders. Bihar graduates (2020-2024 cohort) are being actively enrolled per state notifications. Central scheme, no state budget line needed.', NULL, NULL, 'https://nats.education.gov.in/about-us.php', '2026-06-22', NULL, '2026-06-22 12:27:36.779072+05:30', '{unemployed_youth,student}', '{iti_diploma,graduate}', 'any', '{}', NULL, NULL, NULL, false, 'any', false, false, NULL, NULL, '{skilling,employment}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('2e5601c4-fc9d-48c1-972e-3d2b9b969239', 'National Family Benefit Scheme (NFBS)', 'राष्ट्रीय परिवार लाभ योजना (NFBS)', 'b9da0199-24c5-4382-b284-74f9e43d390c', NULL, 'One-time ex-gratia to a BPL family on the death of its primary breadwinner (district-administered, under NSAP).', 'मुख्य कमाने वाले की मृत्यु पर BPL परिवार को एकमुश्त अनुग्रह राशि (ज़िला-प्रशासित, NSAP के अंतर्गत)।', 'BPL family in Bihar whose primary breadwinner (aged 18–59) has died; applied at the district level.', 'बिहार का BPL परिवार जिसके मुख्य कमाने वाले (आयु 18–59) की मृत्यु हुई हो; ज़िला स्तर पर आवेदन।', 'Ex-gratia (lump sum)', 'Reported ₹20,000 one-time. Verify current amount at the district welfare office.', 'BPL families of Bihar.', 'https://nsap.nic.in', 'active', 'Active — operating under NSAP with ~3.5 lakh beneficiaries; ₹20,000 one-time on death of a BPL family''s primary breadwinner, DBT-delivered (PIB/NSAP 2025). Verified 2026-06-19. Source: https://nsap.nic.in/', NULL, NULL, 'https://nsap.nic.in', '2026-06-19', NULL, '2026-06-19 18:16:08.400442+05:30', '{}', '{}', 'any', '{}', NULL, NULL, NULL, true, 'bihar', false, false, NULL, NULL, '{social_welfare}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('faa6ac4a-e2b4-4c37-97c6-be8b142a2cdd', 'Niramaya Health Insurance Scheme', 'निरामय स्वास्थ्य बीमा योजना', '7c55a28b-5299-455c-b4e6-8d1f12154af5', NULL, 'Provide affordable health insurance to persons with developmental disabilities (autism, cerebral palsy, intellectual disability and multiple disabilities) covering medical needs across the lifespan.', 'विकासात्मक दिव्यांगता (ऑटिज़्म, सेरेब्रल पाल्सी, बौद्धिक दिव्यांगता, बहु-दिव्यांगता) वाले व्यक्तियों को किफायती स्वास्थ्य बीमा उपलब्ध कराना।', 'Persons with disabilities covered under the National Trust Act (autism, cerebral palsy, mental retardation/intellectual disability, multiple disabilities) holding a valid disability certificate / UDID card or enrolment, registered with the National Trust. No income ceiling; premium varies by BPL/APL status.', 'राष्ट्रीय न्यास अधिनियम के अंतर्गत आने वाले दिव्यांग व्यक्ति (ऑटिज़्म, सेरेब्रल पाल्सी, बौद्धिक दिव्यांगता, बहु-दिव्यांगता) जिनके पास वैध दिव्यांगता/UDID प्रमाण-पत्र हो एवं जो राष्ट्रीय न्यास में पंजीकृत हों। कोई आय-सीमा नहीं; प्रीमियम BPL/APL के अनुसार।', 'insurance', 'Health insurance cover up to ₹1,00,000 per year (reimbursement basis) with sub-limits: hospitalisation/corrective surgeries (₹55,000), OPD incl. medicines/pathology/diagnostics and preventive dentistry (₹19,000), ongoing therapies (₹20,000), alternative/AYUSH medicine (₹4,000) and transportation (₹2,000). No exclusion for pre-existing conditions; no pre-insurance medical test.', 'Persons with disabilities (National Trust Act)', NULL, 'active', 'Fetched the National Trust Niramaya page (nationaltrust.nic.in/niramaya), which shows current coverage amounts, sub-limits, and a live claims helpline, indicating an actively administered scheme. Applies nationwide including Bihar residents registered with the National Trust.', NULL, NULL, 'https://nationaltrust.nic.in/niramaya/', '2026-06-22', NULL, '2026-06-22 12:27:36.779072+05:30', '{}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'any', true, false, NULL, NULL, '{health,social_welfare}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('ca779c0c-d315-4119-8666-ac370c48498c', 'PM Formalisation of Micro Food Processing Enterprises (PMFME)', 'प्रधानमंत्री सूक्ष्म खाद्य उद्यम उन्नयन योजना (PMFME)', '019ce852-a68d-4158-bfe7-d74714fc9306', '2020-06-29', 'Enhance the competitiveness of existing micro food-processing enterprises and bring them into the formal economy through credit-linked capital subsidies, technical support, and capacity building.', 'मौजूदा सूक्ष्म खाद्य प्रसंस्करण उद्यमों की प्रतिस्पर्धात्मकता बढ़ाना और ऋण-संबद्ध पूंजी सब्सिडी, तकनीकी सहायता एवं क्षमता निर्माण के माध्यम से उन्हें औपचारिक अर्थव्यवस्था में लाना।', 'Existing individual micro food processing enterprises, proprietorships, partnerships, FPOs, SHGs, producer cooperatives, and self-help groups engaged in food processing. Open to Bihar-based units — state implementation through Bihar''s nodal agency.', 'मौजूदा सूक्ष्म खाद्य प्रसंस्करण इकाइयाँ, एकल-स्वामित्व/भागीदारी, FPO, SHG, उत्पादक सहकारी समितियाँ एवं स्वयं-सहायता समूह। बिहार की इकाइयाँ राज्य की नोडल एजेंसी के माध्यम से पात्र।', 'subsidy', 'Credit-linked capital subsidy of 35% of eligible project cost up to Rs. 10 lakh per micro unit; seed capital of Rs. 40,000 per SHG member for working capital and small tools; grants for FPOs/SHGs/co-operatives for common infrastructure; branding and marketing support.', 'Micro food-processing enterprises', 'https://pmfme.mofpi.gov.in', 'active', 'Fetched official MoFPI PMFME page (mofpi.gov.in/en/pmfme/seed-capital-shg): describes PMFME as a current central sector scheme launched 29 June 2020 with a 5-year outlay (2020-21 to 2024-25) and an online application portal (pmfme.mofpi.gov.in). Scheme extended and operational per MoFPI 2024 annual report and PIB releases through 2025.', NULL, NULL, 'https://mofpi.gov.in/en/pmfme/seed-capital-shg', '2026-06-22', NULL, '2026-06-22 13:06:26.932232+05:30', '{self_employed_entrepreneur,shg_jeevika_member,farmer}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'any', false, false, NULL, NULL, '{industry,skilling,financial_inclusion,agriculture}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('7c89d489-df93-4c68-8e0b-2140eeec2da4', 'PM-KISAN (Pradhan Mantri Kisan Samman Nidhi)', 'पीएम-किसान (प्रधानमंत्री किसान सम्मान निधि)', '76bf5c89-0e98-4a01-98ff-d0de1281611f', NULL, 'Central income support to landholding farmer families.', 'भूमिधारी किसान परिवारों को केंद्रीय आय-सहायता।', 'Landholding farmer families (with cultivable land), subject to exclusion criteria (income-tax payers, institutional landholders etc.). Registered on the PM-KISAN portal.', 'खेती योग्य भूमि वाले किसान परिवार, अपवर्जन मानदंड सहित (आयकरदाता, संस्थागत भूधारक आदि)। पीएम-किसान पोर्टल पर पंजीकृत।', 'Income support (DBT)', '₹6,000/year in three ₹2,000 installments. Verify current status at the portal.', 'Landholding farmer families.', 'https://pmkisan.gov.in', 'active', 'Active — 22nd installment released 13 Mar 2026 (₹18,640 cr to 9.32 crore farmers; cumulative >₹4.27 lakh crore, per PIB); 23rd installment scheduled 20 Jun 2026. ₹6,000/year in three ₹2,000 installments; eKYC mandatory. Verified 2026-06-19. Source: https://pmkisan.gov.in/', NULL, '2026-03-13', 'https://pmkisan.gov.in', '2026-06-19', NULL, '2026-06-19 18:09:43.685318+05:30', '{farmer}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'any', false, false, 'raiyat', NULL, '{agriculture,financial_inclusion}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('304b507e-057f-4eb3-92c3-6a9361a62a75', 'PM POSHAN (Mid-Day Meal)', 'पीएम पोषण (मध्याह्न भोजन)', '76bf5c89-0e98-4a01-98ff-d0de1281611f', NULL, 'Hot cooked meals to school children to improve nutrition and attendance.', 'पोषण व उपस्थिति सुधारने हेतु विद्यालयी बच्चों को गर्म पका भोजन।', 'Children in government and government-aided schools (Bal Vatika to Class 8).', 'सरकारी व सरकारी-सहायता प्राप्त विद्यालयों के बच्चे (बाल वाटिका से कक्षा 8)।', 'School meals', 'One hot cooked meal per school day, per nutrition norms.', 'Government-school children.', 'https://pmposhan.education.gov.in', 'active', 'Active — material cost revised +9.5% effective 1 May 2025 (~₹954 cr extra in FY2025-26); one hot cooked meal per school day, Bal Vatika–Class 8. Sanctioned through FY2025-26 (continuation beyond Mar 2026 needs fresh approval). Verified 2026-06-19. Source: https://pmposhan.education.gov.in/', NULL, NULL, 'https://pmposhan.education.gov.in', '2026-06-19', NULL, '2026-06-19 18:23:33.641354+05:30', '{student}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'any', false, false, NULL, NULL, '{education,health,women_child}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('ffe0795f-5bdd-4708-9903-a6a7e0c48982', 'PM SVANidhi (Street Vendors)', 'पीएम स्वनिधि (पथ विक्रेता)', '76bf5c89-0e98-4a01-98ff-d0de1281611f', NULL, 'Collateral-free working-capital loans for urban street vendors.', 'शहरी पथ विक्रेताओं हेतु बिना गारंटी कार्यशील-पूंजी ऋण।', 'Urban street vendors with a vending certificate/identity (or per survey).', 'वेंडिंग प्रमाण-पत्र/पहचान वाले शहरी पथ विक्रेता (या सर्वेक्षण अनुसार)।', 'Working-capital loan', 'Collateral-free working-capital loans for street vendors — ₹15,000, then ₹25,000, then ₹50,000 (tiers raised in the 2025 restructuring), with interest subsidy; repaying the 2nd loan unlocks a UPI-linked RuPay credit card.', 'Urban street vendors.', 'https://pmsvanidhi.mohua.gov.in', 'active', 'Active — Cabinet restructured and extended it to 31 Mar 2030 (₹7,332 cr, Aug 2025); ~96 lakh loans disbursed by Jul 2025. Verified 2026-06-19. Source: https://pmsvanidhi.mohua.gov.in/', NULL, NULL, 'https://pmsvanidhi.mohua.gov.in', '2026-06-19', NULL, '2026-06-19 18:09:43.698897+05:30', '{self_employed_entrepreneur}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'any', false, false, NULL, NULL, '{financial_inclusion,employment}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('b287155a-1b6e-474c-95ed-b1ce3e471fcc', 'PM Vishwakarma', 'पीएम विश्वकर्मा', '76bf5c89-0e98-4a01-98ff-d0de1281611f', NULL, 'Support to traditional artisans and craftspeople — recognition, skilling, toolkit and credit.', 'पारंपरिक शिल्पकारों एवं कारीगरों को सहायता — मान्यता, कौशल, टूलकिट एवं ऋण।', 'Artisans/craftspeople in one of the notified trades (carpenter, blacksmith, potter, weaver, etc.); family/occupation criteria apply.', 'अधिसूचित व्यवसायों (बढ़ई, लोहार, कुम्हार, बुनकर आदि) के शिल्पकार/कारीगर; परिवार/व्यवसाय मानदंड लागू।', 'Skilling + toolkit + collateral-free loan', '₹500/day training stipend, a ₹15,000 toolkit incentive, and collateral-free loans up to ₹3 lakh (₹1 lakh then ₹2 lakh) at 5% interest.', 'Traditional artisans and craftspeople.', 'https://pmvishwakarma.gov.in', 'active', 'Active — 30+ lakh artisans registered and 4.7 lakh loans sanctioned by Aug 2025 (PIB). Verified 2026-06-19. Source: https://pmvishwakarma.gov.in/', NULL, NULL, 'https://pmvishwakarma.gov.in', '2026-06-19', NULL, '2026-06-19 18:09:43.6964+05:30', '{artisan_weaver}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'any', false, false, NULL, NULL, '{skilling,financial_inclusion,industry}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('1ea75d8d-b5f7-46f2-834c-31ab3faffc24', 'Pradhan Mantri Awas Yojana — Gramin (PMAY-G)', 'प्रधानमंत्री आवास योजना — ग्रामीण (PMAY-G)', '76bf5c89-0e98-4a01-98ff-d0de1281611f', NULL, 'Assistance to rural houseless / kutcha-house families to build a pucca house.', 'ग्रामीण बेघर/कच्चे-मकान परिवारों को पक्का मकान बनाने हेतु सहायता।', 'Rural families without a pucca house, identified per SECC/Awas+ lists.', 'पक्के मकान से वंचित ग्रामीण परिवार, SECC/आवास+ सूची अनुसार।', 'Housing assistance (DBT)', 'Reported ~₹1.20 lakh (plains) / ₹1.30 lakh (hilly/difficult) + MGNREGA wage days + toilet support. Verify current terms.', 'Rural houseless/kutcha-house families.', 'https://pmayg.nic.in', 'active', 'Active — budget line ₹4,320 cr (2025-26 BE) under Rural Development, per the Bihar Budget Documents (PRS analysis). The 2026-27 PRS analysis does not separately itemise PMAY-G, so the latest confirmed line is 2025-26. Verified 2026-06-19.', '2025-26', NULL, 'https://pmayg.nic.in', '2026-06-19', NULL, '2026-06-19 18:09:43.692025+05:30', '{}', '{}', 'any', '{}', NULL, NULL, NULL, true, 'any', false, false, NULL, NULL, '{housing,social_welfare}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('dd7ca793-5bce-4f4a-9d4d-86122bb5977d', 'Pradhan Mantri Awas Yojana — Urban (PMAY-U)', 'प्रधानमंत्री आवास योजना — शहरी (PMAY-U)', '76bf5c89-0e98-4a01-98ff-d0de1281611f', NULL, 'Housing assistance/interest subsidy for urban EWS/LIG/MIG families.', 'शहरी EWS/LIG/MIG परिवारों हेतु आवास सहायता/ब्याज सब्सिडी।', 'Urban EWS/LIG/MIG households without a pucca house (income-based slabs). Verify slabs at the portal.', 'पक्के मकान से वंचित शहरी EWS/LIG/MIG परिवार (आय-आधारित स्लैब)। स्लैब पोर्टल पर सत्यापित करें।', 'Housing assistance / interest subsidy', 'Credit-linked interest subsidy / construction assistance for eligible income groups. Verify current terms.', 'Urban EWS/LIG/MIG families.', 'https://pmay-urban.gov.in', 'active', 'Active — budget line ₹2,355 cr (2025-26 BE) rising to ₹2,842 cr (2026-27 BE) under Urban Development, per the Bihar Budget Documents (PRS analysis). A current-fiscal-year allocation is present. Verified 2026-06-19.', '2026-27', NULL, 'https://pmay-urban.gov.in', '2026-06-19', NULL, '2026-06-19 18:09:43.693607+05:30', '{}', '{}', 'any', '{}', NULL, NULL, 600000, false, 'any', false, false, NULL, NULL, '{housing}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('3a00bafd-abb3-4c87-8c8b-84e45a5de3f7', 'Pradhan Mantri Jan Dhan Yojana (PMJDY)', 'प्रधानमंत्री जन धन योजना (PMJDY)', '76bf5c89-0e98-4a01-98ff-d0de1281611f', NULL, 'Universal access to a basic bank account with overdraft, insurance and DBT linkage.', 'ओवरड्राफ्ट, बीमा एवं DBT लिंकेज सहित बुनियादी बैंक खाते तक सार्वभौमिक पहुँच।', 'Any Indian resident without a bank account (zero-balance account).', 'बिना बैंक खाते वाला कोई भी भारतीय निवासी (शून्य-शेष खाता)।', 'Zero-balance bank account', 'Zero-balance account with RuPay card, overdraft up to ₹10,000, and ₹2 lakh accidental insurance cover.', 'Unbanked residents.', 'https://pmjdy.gov.in', 'active', 'Active — 11 years in 2025: 56.16 crore accounts and 38.68 crore RuPay cards (PIB, Aug 2025). Verified 2026-06-19. Source: https://pmjdy.gov.in/', NULL, NULL, 'https://pmjdy.gov.in', '2026-06-19', NULL, '2026-06-19 18:23:33.644764+05:30', '{}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'any', false, false, NULL, NULL, '{financial_inclusion}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('68f99c52-fcd7-4220-8706-e84ce4fdc33e', 'Affordable Rental Housing Complexes (ARHCs)', 'किफायती किराया आवास परिसर योजना', 'ea34d531-d72f-4e7e-b234-963c11274cc0', '2020-07-08', 'Provide affordable subsidised rental housing to urban migrants and urban poor (EWS/LIG) near their workplaces, reducing distress and unsafe living conditions for industrial and construction workers, street vendors, and similar groups.', 'शहरी प्रवासियों एवं शहरी गरीबों (EWS/LIG) को उनके कार्यस्थल के निकट किफायती किराया आवास उपलब्ध कराना, ताकि औद्योगिक/निर्माण श्रमिकों, रेहड़ी-पटरी वालों आदि की परेशानी एवं असुरक्षित आवास की स्थिति कम हो सके।', 'Urban migrants and urban poor in the EWS / LIG categories — including industrial workers, construction workers, street vendors, rickshaw pullers, market/trade workers — seeking affordable rental housing near their workplace in urban areas.', 'EWS/LIG श्रेणी के शहरी प्रवासी एवं शहरी गरीब — जैसे औद्योगिक/निर्माण श्रमिक, रेहड़ी-पटरी वाले, रिक्शा चालक, बाजार/व्यापार कर्मी — जो शहरी क्षेत्र में कार्यस्थल के निकट किफायती किराया आवास चाहते हों।', 'subsidised housing', 'Access to subsidised rental housing in ARHCs comprising single-bedroom (~30 sq m) and double-bedroom (~60 sq m) dwelling units plus 4-6 bed dormitories, at affordable rents. Complexes developed on existing government-funded vacant housing stock or by private/public entities on their own land through PPP.', 'Urban migrants and urban poor (EWS/LIG)', NULL, 'likely_active', 'Fetched official PMAY-Urban ARHC page (pmay-urban.gov.in/arhc-about): launched 8 July 2020 under PMAY-Urban as a sub-scheme for urban migrants/poor; Model 1 (govt housing stock) and Model 2 (private/public land) operational; cities listed Bihar among potential implementation states. No current-FY Bihar-specific budget confirmation found — likely_active. Distinct from PMAY-Urban (ownership housing) — ARHC is specifically a rental sub-scheme.', NULL, NULL, 'https://pmay-urban.gov.in/arhc-about', '2026-06-22', NULL, '2026-06-22 13:06:26.932232+05:30', '{worker_labourer,unemployed_youth}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'any', false, false, NULL, NULL, '{housing,social_welfare,employment}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('4da51709-4301-4c84-9088-48c89b2867cd', 'Bihar Har Ghar Bijli Yojana', 'बिहार हर घर बिजली योजना', '79edbbf6-0b00-41ac-8050-3d3e99d0a5de', NULL, 'Free electricity connection to every un-electrified household in Bihar.', 'बिहार के प्रत्येक अविद्युतीकृत घर को नि:शुल्क बिजली कनेक्शन।', 'Un-electrified households in Bihar (BPL households get free connection).', 'बिहार के अविद्युतीकृत घर (BPL परिवारों को नि:शुल्क कनेक्शन)।', 'Electricity connection', 'Free new domestic electricity connection (the portal stays open for unconnected households). Bihar also gives 125 free units/month to domestic consumers from Aug 2025.', 'Un-electrified households of Bihar.', 'https://hargharbijli.bsphcl.co.in', 'likely_active', 'Likely active — universal household electrification was achieved Oct 2018 (a saturation scheme); BSPHCL''s portal stays open for new/missed households. A separate 125-free-units/month benefit began Aug 2025. Verified 2026-06-19. Source: https://hargharbijli.bsphcl.co.in/', NULL, NULL, 'https://energy.bihar.gov.in', '2026-06-19', NULL, '2026-06-19 17:38:29.854027+05:30', '{}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'bihar', false, false, NULL, NULL, '{social_welfare}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('d3023f29-f7df-4ba7-9b52-a2adcebf2b0c', 'Pradhan Mantri Jeevan Jyoti Bima Yojana (PMJJBY)', 'प्रधानमंत्री जीवन ज्योति बीमा योजना (PMJJBY)', '76bf5c89-0e98-4a01-98ff-d0de1281611f', NULL, 'Affordable life-insurance cover via a bank account.', 'बैंक खाते के माध्यम से किफायती जीवन बीमा।', 'Bank account holders aged 18–50 who auto-debit the premium.', '18–50 आयु के बैंक खाताधारक जो प्रीमियम ऑटो-डेबिट करें।', 'Life insurance', 'Life cover of ₹2 lakh for an annual premium of ₹436 (revised 2022); bank-account holders aged 18–50.', 'Bank account holders (18–50).', 'https://www.jansuraksha.gov.in', 'active', 'Active — runs under the Jan Suraksha umbrella (PMJJBY + PMSBY enrolments past 55 crore by 2026); premium ₹436/year since 1 Jun 2022 (PIB). Verified 2026-06-19. Source: https://www.jansuraksha.gov.in/', NULL, NULL, 'https://www.jansuraksha.gov.in', '2026-06-19', NULL, '2026-06-19 18:23:33.63137+05:30', '{}', '{}', 'any', '{}', 18, 50, NULL, false, 'any', false, false, NULL, NULL, '{financial_inclusion,social_welfare}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('65302e61-337a-4e92-9745-4933176f6896', 'Pradhan Mantri Kaushal Vikas Yojana (PMKVY)', 'प्रधानमंत्री कौशल विकास योजना (PMKVY)', '76bf5c89-0e98-4a01-98ff-d0de1281611f', NULL, 'Short-term skill training and certification for youth to improve employability.', 'रोज़गार-योग्यता बढ़ाने हेतु युवाओं को अल्पकालिक कौशल प्रशिक्षण व प्रमाणन।', 'Indian youth (typically 15–45) seeking skill training; criteria vary by job role.', 'कौशल प्रशिक्षण चाहने वाले भारतीय युवा (सामान्यतः 15–45); भूमिका अनुसार मानदंड।', 'Free skill training + certification', 'Free NSQF-aligned training, assessment and certification (placement support). Verify current terms.', 'Youth seeking skills.', 'https://www.pmkvyofficial.org', 'active', 'Active — PMKVY 4.0 runs under the restructured Skill India Programme (Cabinet, Feb 2025) through FY2025-26, relaunch confirmed Mar 2026; free NSQF training + certification (also on skillindiadigital.gov.in). Verified 2026-06-19. Source: https://www.pmkvyofficial.org/', NULL, NULL, 'https://www.pmkvyofficial.org', '2026-06-19', NULL, '2026-06-19 18:23:33.63807+05:30', '{unemployed_youth}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'any', false, false, NULL, NULL, '{skilling,employment}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('46c7bb62-b2f9-4952-a1bc-2385d8a93ba1', 'Pradhan Mantri Matru Vandana Yojana (PMMVY)', 'प्रधानमंत्री मातृ वंदना योजना (PMMVY)', '76bf5c89-0e98-4a01-98ff-d0de1281611f', NULL, 'Maternity benefit / wage compensation for pregnant and lactating women.', 'गर्भवती व स्तनपान कराने वाली महिलाओं हेतु मातृत्व लाभ / मज़दूरी क्षतिपूर्ति।', 'Pregnant and lactating women for the first (and per current norms, second girl) child.', 'पहले (एवं वर्तमान मानदंड अनुसार दूसरी बालिका) बच्चे हेतु गर्भवती व स्तनपान कराने वाली महिलाएँ।', 'Maternity benefit (DBT)', '₹5,000 for the first child (in two installments); an additional ₹6,000 for a second child if a girl. Paid by DBT.', 'Pregnant and lactating women.', 'https://pmmvy.wcd.gov.in/', 'active', 'Active — special registration drive extended to 15 Aug 2025 (PIB). Verified 2026-06-19. Source: https://pmmvy.wcd.gov.in/', NULL, NULL, 'https://wcd.nic.in', '2026-06-19', NULL, '2026-06-19 18:23:33.643488+05:30', '{pregnant_lactating_woman}', '{}', 'female', '{}', NULL, NULL, NULL, false, 'any', false, false, NULL, NULL, '{women_child,health}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('5fe8d624-2354-4ac0-9855-e4bde320de4c', 'Pradhan Mantri Mudra Yojana (PMMY)', 'प्रधानमंत्री मुद्रा योजना (PMMY)', '76bf5c89-0e98-4a01-98ff-d0de1281611f', NULL, 'Collateral-free micro-loans for non-farm income-generating micro/small enterprises.', 'गैर-कृषि आय-सृजन सूक्ष्म/लघु उद्यमों हेतु बिना गारंटी सूक्ष्म-ऋण।', 'Non-corporate, non-farm micro/small enterprises and aspiring entrepreneurs (via banks/MFIs/NBFCs).', 'गैर-कॉर्पोरेट, गैर-कृषि सूक्ष्म/लघु उद्यम एवं इच्छुक उद्यमी (बैंक/MFI/NBFC के माध्यम से)।', 'Collateral-free loan', 'Loans under Shishu (≤₹50k), Kishore (₹50k–₹5L), Tarun (₹5L–₹10L) and Tarun Plus (₹10L–₹20L, for borrowers who have repaid a Tarun loan). Collateral-free, CGFMU-guaranteed.', 'Micro/small entrepreneurs.', 'https://www.mudra.org.in', 'active', 'Active — loan limit doubled to ₹20 lakh via the new Tarun Plus category (effective 24 Oct 2024, PIB). Verified 2026-06-19. Source: https://www.mudra.org.in/', NULL, NULL, 'https://www.mudra.org.in', '2026-06-19', NULL, '2026-06-19 18:09:43.701155+05:30', '{self_employed_entrepreneur}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'any', false, false, NULL, NULL, '{financial_inclusion,employment}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('321b94f2-1db1-4eca-8534-94b0f3040429', 'Pradhan Mantri National Dialysis Programme (PMNDP)', 'प्रधानमंत्री राष्ट्रीय डायलिसिस कार्यक्रम', 'fd286a59-bc47-46e3-b355-d3bec3bdd2c9', '2016-04-07', 'Make renal-care/dialysis services accessible and affordable to poor (BPL) patients with chronic kidney disease / end-stage renal disease, addressing the financial burden of recurring dialysis.', 'गुर्दा रोग से ग्रस्त गरीब (BPL) रोगियों के लिए डायलिसिस सेवाएँ सुलभ एवं किफायती बनाना, बार-बार होने वाले खर्च के बोझ को कम करना।', 'Below Poverty Line patients needing dialysis — eligibility evidenced by a National Food Security card or an income certificate showing annual income below ₹1 lakh, per search-sourced guidance.', 'डायलिसिस की आवश्यकता वाले गरीबी-रेखा-से-नीचे (BPL) रोगी — राष्ट्रीय खाद्य सुरक्षा कार्ड या वार्षिक आय 1 लाख रु. से कम का प्रमाण-पत्र द्वारा पात्रता।', 'free service', 'Free dialysis services at district hospitals (in PPP and in-house modes), covering both haemodialysis and peritoneal dialysis. For BPL economic group, 100% of expenses are covered under NHM by the government.', 'BPL dialysis patients', NULL, 'active', 'Fetched the official MoHFW PMNDP portal introduction page (pmndp.mohfw.gov.in), describing it as launched 7 April 2016, currently operating across States/UTs in PPP/in-house/hybrid modes with a live PMNDP IT portal (launched May 2022). Bihar-specific reporting (State Health Society Bihar data cited in press) shows active district dialysis centres with sessions delivered as recently as 2024, confirming the program runs in Bihar.', NULL, NULL, 'https://pmndp.mohfw.gov.in/en/introduction-of-pradhan-mantri-national-dialysis-program-pmndp', '2026-06-22', NULL, '2026-06-22 12:27:36.779072+05:30', '{}', '{}', 'any', '{}', NULL, NULL, NULL, true, 'any', false, false, NULL, NULL, '{health}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('20d461f0-b31d-4945-b2d8-bdfa1ce6174f', 'Pradhan Mantri Shram Yogi Maandhan (PM-SYM)', 'प्रधानमंत्री श्रम योगी मानधन (PM-SYM)', '76bf5c89-0e98-4a01-98ff-d0de1281611f', NULL, 'Voluntary contributory pension for unorganised-sector workers.', 'असंगठित क्षेत्र के श्रमिकों हेतु स्वैच्छिक अंशदायी पेंशन।', 'Unorganised-sector workers aged 18–40 with monthly income up to ₹15,000 (non-EPF/ESIC/NPS).', '18–40 आयु के असंगठित श्रमिक, मासिक आय ₹15,000 तक (EPF/ESIC/NPS में नहीं)।', 'Guaranteed pension', 'Assured ₹3,000/month pension after age 60 (50% govt co-contribution). Verify current terms.', 'Unorganised-sector workers (18–40).', 'https://maandhan.in', 'active', 'Active — Ministry of Labour confirms operation (PIB 2025): ₹3,000/month pension after 60 with equal (50%) government co-contribution, for unorganised workers 18–40 earning ≤₹15,000/month and not in EPFO/ESIC/NPS. Verified 2026-06-19. Source: https://maandhan.in/', NULL, NULL, 'https://maandhan.in', '2026-06-19', NULL, '2026-06-19 18:23:33.636501+05:30', '{worker_labourer}', '{}', 'any', '{}', 18, 40, 180000, false, 'any', false, false, NULL, NULL, '{social_welfare,financial_inclusion}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('4a9faf18-1c61-448a-8982-4c2085d5745e', 'Pradhan Mantri Suraksha Bima Yojana (PMSBY)', 'प्रधानमंत्री सुरक्षा बीमा योजना (PMSBY)', '76bf5c89-0e98-4a01-98ff-d0de1281611f', NULL, 'Affordable accident-insurance cover via a bank account.', 'बैंक खाते के माध्यम से किफायती दुर्घटना बीमा।', 'Bank account holders aged 18–70 who auto-debit the premium.', '18–70 आयु के बैंक खाताधारक जो प्रीमियम ऑटो-डेबिट करें।', 'Accident insurance', 'Accidental death/disability cover of ₹2 lakh for an annual premium of ₹20; bank-account holders aged 18–70.', 'Bank account holders (18–70).', 'https://www.jansuraksha.gov.in', 'active', 'Active — Jan Suraksha umbrella, 55+ crore combined enrolments (2026); premium ₹20/year since 1 Jun 2022 (PIB). Verified 2026-06-19. Source: https://www.jansuraksha.gov.in/', NULL, NULL, 'https://www.jansuraksha.gov.in', '2026-06-19', NULL, '2026-06-19 18:23:33.635078+05:30', '{}', '{}', 'any', '{}', 18, 70, NULL, false, 'any', false, false, NULL, NULL, '{financial_inclusion,social_welfare}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('46cc6625-82fc-4511-9489-08c98e84419a', 'Jan Shikshan Sansthan (JSS) Scheme', 'जन शिक्षण संस्थान योजना', '817d71b3-62ce-4f42-aa5d-63f4042953ac', NULL, 'Provide vocational and technical training to non-literates, neo-literates, and school dropouts (especially women) from weaker sections in rural and urban areas, to improve their livelihood through skill development.', 'ग्रामीण एवं शहरी क्षेत्रों के कमज़ोर वर्गों के निरक्षर, नव-साक्षर एवं स्कूल छोड़ चुके व्यक्तियों (विशेषकर महिलाओं) को व्यावसायिक एवं तकनीकी प्रशिक्षण देकर कौशल-विकास के माध्यम से उनकी आजीविका में सुधार करना।', 'Non-literates, neo-literates and persons with rudimentary education / school dropouts up to class 12, generally aged 15-45, from weaker sections; special focus on women, SC/ST and minority communities. Implemented through JSS institutes in districts across Bihar.', 'निरक्षर, नव-साक्षर एवं प्राथमिक/माध्यमिक शिक्षा तक के व्यक्ति (कक्षा 12 तक स्कूल छोड़ चुके), सामान्यतः 15-45 आयु, कमज़ोर वर्गों से; महिलाओं, SC/ST एवं अल्पसंख्यकों पर विशेष ध्यान। बिहार के जिलों में JSS संस्थाओं के माध्यम से कार्यान्वित।', 'training', 'Free or heavily subsidised short vocational courses (typically 2-6 months) in trades such as tailoring, beauty culture, food processing, electrical work, plumbing, and mobile repair. Training delivered locally through Jan Shikshan Sansthan institutes established in districts.', 'Non-literate / school-dropout adults (esp. women, weaker sections)', NULL, 'active', 'Official MSDE scheme page (msde.gov.in/offerings/schemes-and-services/details/jan-shikshan-sansthan-jss) lists JSS as a current MSDE scheme with established institutes nationwide including Bihar. PIB and Union Budget documents confirm JSS continuation with allocations through 2025-26. Active JSS institutes operate in Bihar districts.', NULL, NULL, 'https://www.msde.gov.in/offerings/schemes-and-services/details/jan-shikshan-sansthan-jss', '2026-06-22', NULL, '2026-06-22 13:06:26.932232+05:30', '{unemployed_youth,worker_labourer}', '{none,primary,secondary}', 'any', '{}', 15, 45, NULL, false, 'any', false, false, NULL, NULL, '{skilling,education,social_welfare}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('26c31ab5-2cff-4b4c-9a4e-84fc715471d8', 'Prime Minister''s Employment Generation Programme (PMEGP)', 'प्रधानमंत्री रोजगार सृजन कार्यक्रम (पीएमईजीपी)', '86bbc815-60b5-46f2-80ce-7b5f03b8a3d7', NULL, 'Generate employment by helping individuals set up new non-agricultural micro-enterprises (manufacturing and service/business units) through a credit-linked margin-money subsidy.', 'ऋण-संबद्ध मार्जिन-मनी सब्सिडी के माध्यम से नए गैर-कृषि सूक्ष्म उद्यम स्थापित करने में सहायता देकर रोजगार सृजन।', 'Any individual above 18 years; for projects above Rs.10 lakh (manufacturing) or Rs.5 lakh (service) the applicant must have passed at least Class VIII. Also open to SHGs, registered institutions/societies, production cooperatives and charitable trusts. Existing units and those who already availed subsidy under another govt scheme are not eligible.', '18 वर्ष से अधिक का कोई भी व्यक्ति; निर्माण में 10 लाख रु. / सेवा में 5 लाख रु. से बड़ी परियोजनाओं हेतु कम-से-कम कक्षा 8 उत्तीर्ण। SHG, पंजीकृत संस्थाएँ, सहकारी समितियाँ एवं ट्रस्ट भी पात्र। मौजूदा इकाइयाँ / पहले से अन्य सब्सिडी प्राप्त इकाइयाँ अपात्र।', 'subsidy', 'Credit-linked margin-money subsidy. General category: 15% (urban) / 25% (rural) of project cost; special category (SC/ST/OBC/minorities/women/ex-servicemen/PwD/NER/hill/border): 25% (urban) / 35% (rural). Max project cost Rs.25 lakh (manufacturing) and Rs.10 lakh (service/business).', 'New micro-entrepreneurs', 'https://www.kviconline.gov.in/pmegpeportal/', 'active', 'Official MSME portal (my.msme.gov.in) and msme.gov.in list PMEGP as a current flagship scheme with a live online application portal (kviconline.gov.in/pmegp). Implemented at state level through Bihar KVIC/KVIB/DIC. Listed as operational for 2025-26.', NULL, NULL, 'https://my.msme.gov.in/MyMsmeMob/MsmeScheme/Pages/1_3_0.html', '2026-06-22', NULL, '2026-06-22 12:27:36.779072+05:30', '{self_employed_entrepreneur,unemployed_youth}', '{}', 'any', '{}', 18, NULL, NULL, false, 'any', false, false, NULL, NULL, '{employment,industry,financial_inclusion}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('abd0379c-2d61-4fc5-91c8-587d5c072e17', 'Mukhyamantri Balika Protsahan Yojana (Matric)', 'मुख्यमंत्री बालिका प्रोत्साहन योजना (मैट्रिक)', 'c6f71956-defd-4037-8324-6c3e805899ba', NULL, 'Cash incentive for girls who pass the Class 10 (Matric) BSEB exam.', 'बिहार बोर्ड से 10वीं (मैट्रिक) उत्तीर्ण बालिकाओं हेतु नकद प्रोत्साहन।', 'Girls of Bihar passing Class 10 from BSEB.', 'बिहार बोर्ड से 10वीं उत्तीर्ण बिहार की बालिकाएँ।', 'Cash incentive', 'Reported ₹10,000 (1st division) / ₹8,000 (2nd division). Verify at the portal.', 'Girls passing Class 10 in Bihar.', 'https://www.medhasoft.bihar.gov.in', 'likely_active', 'Likely active — a Class-10 first-division incentive (reported ₹10,000) is running via medhasoft for 2025; recent reporting suggests it may now cover all first-division students (not girls only), so the exact gender scope needs confirmation. Verified 2026-06-19. Source: https://medhasoft.bihar.gov.in/', NULL, NULL, 'https://www.medhasoft.bihar.gov.in', '2026-06-19', NULL, '2026-06-19 17:38:29.833519+05:30', '{student}', '{secondary}', 'female', '{}', NULL, NULL, NULL, false, 'bihar', false, false, NULL, NULL, '{education,women_child}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('429ffcfc-4255-476b-aa26-260b82eba509', 'Rajiv Gandhi Grameen Vidyutikaran Yojana (RGGVY)', 'राजीव गांधी ग्रामीण विद्युतीकरण योजना (RGGVY)', '76bf5c89-0e98-4a01-98ff-d0de1281611f', NULL, 'Earlier central rural electrification scheme.', 'पूर्ववर्ती केंद्रीय ग्रामीण विद्युतीकरण योजना।', 'Un-electrified rural areas/households (historical scheme).', 'अविद्युतीकृत ग्रामीण क्षेत्र/घर (ऐतिहासिक योजना)।', 'Rural electrification', 'Funded rural electrification infrastructure (subsumed into DDUGJY).', 'Un-electrified rural households.', NULL, 'subsumed', 'Subsumed — RGGVY was subsumed into the Deen Dayal Upadhyaya Gram Jyoti Yojana (DDUGJY) as its rural-electrification component (2014-15); household electrification later continued under Saubhagya (Oct 2017). Verified 2026-06-19. Source: https://www.pib.gov.in/PressReleasePage.aspx?PRID=1883918', NULL, NULL, 'https://powermin.gov.in', '2026-06-19', NULL, '2026-06-19 18:13:52.064466+05:30', '{}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'any', false, false, NULL, NULL, '{social_welfare}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('16a0261b-4882-46b4-be78-c8e19202a06f', 'Rashtriya Bal Swasthya Karyakram (RBSK)', 'राष्ट्रीय बाल स्वास्थ्य कार्यक्रम', 'f99905da-40dd-4df9-93cc-4c6acb3516e1', NULL, 'Improve children''s quality of life through early identification and free intervention for the 4 Ds — Defects at birth, Diseases, Deficiencies, and Development delays/disability.', '4 ''D'' — जन्मजात दोष, रोग, कमियाँ एवं विकास-संबंधी देरी/दिव्यांगता — की शीघ्र पहचान एवं नि:शुल्क उपचार से बच्चों का स्वास्थ्य सुधारना।', 'Children from birth to 18 years: 0-6 years in the community/anganwadi, and children enrolled in government and government-aided schools (classes I-XII). No income test.', 'जन्म से 18 वर्ष तक के बच्चे: 0–6 वर्ष आँगनबाड़ी/समुदाय में, तथा सरकारी एवं सरकारी-सहायता प्राप्त विद्यालयों (कक्षा 1–12) के बच्चे। कोई आय-परीक्षण नहीं।', 'free service', 'Free screening of children for 30+ health conditions across the 4 Ds, plus free treatment and management including tertiary-level surgeries (e.g. congenital heart disease, cleft lip/palate, club foot, cataract, hearing impairment) and early-intervention services. All services free of cost; delivered via block-level mobile health teams and District Early Intervention Centres.', 'Children (0–18 years)', NULL, 'active', 'Fetched the NHM RBSK page (nhm.gov.in, level=0 linkid=499 lid=773), which describes RBSK as a current NHM child-health program with active mobile health teams and District Early Intervention Centres providing free screening and treatment. An NHM RBSK directory lists Bihar among implementing states.', NULL, NULL, 'https://nhm.gov.in/index1.php?lang=1&level=0&linkid=499&lid=773', '2026-06-22', NULL, '2026-06-22 12:27:36.779072+05:30', '{}', '{}', 'any', '{}', 0, 18, NULL, false, 'any', false, false, NULL, NULL, '{health,women_child}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('b3396608-e6ed-4f88-be46-83cfe0ee11ef', 'Rural Self Employment Training Institutes (RSETI) - Bihar', 'ग्रामीण स्वरोजगार प्रशिक्षण संस्थान', '96a1f1b9-3154-4653-bf38-1829f71c9911', NULL, 'Establish a dedicated RSETI in each district to impart short-term skill training oriented towards entrepreneurship/self-employment for rural unemployed youth, with long-term handholding for setting up micro-enterprises.', 'प्रत्येक जिले में एक RSETI स्थापित कर ग्रामीण बेरोजगार युवाओं को स्वरोजगार-उन्मुख अल्पकालिक कौशल प्रशिक्षण देना, सूक्ष्म उद्यम स्थापना हेतु दीर्घकालिक सहायता के साथ।', 'Rural poor unemployed youth aged 18-45 (priority to BPL households and NRLM/SHG members), enrolled through the district RSETI free of cost. Applicable to rural Bihar residents through the RSETIs operating in Bihar districts.', '18–45 वर्ष के ग्रामीण गरीब बेरोजगार युवा (BPL परिवारों एवं NRLM/SHG सदस्यों को प्राथमिकता), जिला RSETI के माध्यम से नि:शुल्क नामांकन। बिहार के जिलों में संचालित RSETI के माध्यम से ग्रामीण निवासियों हेतु।', 'training', 'Free short-term residential skill training (from a basket of ~64 NCVET/MoRD-approved trades such as tailoring, dairy, electronics repair, apparel), followed by long-term handholding and credit-linkage support to start a self-employment venture. Reported settlement (self-employment/wage-employment) rate above 70%.', 'Rural unemployed youth (18–45)', 'https://dashboard.rural.nic.in/dashboardnew/rseti.aspx', 'active', 'NIRDPR/MoRD official RSETI portal confirms the scheme is operational with district institutes, bank management, approved trades and progress reporting; PIB (2024) notes 590 RSETIs functioning across 572 districts in 33 States/UTs. MoRD national scheme, with RSETIs present in Bihar districts; dashboard.rural.nic.in carries state/district RSETI data including Bihar.', NULL, NULL, 'https://nirdpr.org.in/rseti/', '2026-06-22', NULL, '2026-06-22 12:27:36.779072+05:30', '{unemployed_youth,shg_jeevika_member}', '{}', 'any', '{}', 18, 45, NULL, false, 'any', false, false, NULL, NULL, '{skilling,employment,financial_inclusion}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('c0fcbda0-8253-47ce-828e-ae7b849f0e97', 'Stand-Up India', 'स्टैंड-अप इंडिया', '76bf5c89-0e98-4a01-98ff-d0de1281611f', NULL, 'Bank loans for greenfield enterprises by SC/ST and women entrepreneurs.', 'SC/ST एवं महिला उद्यमियों के नए उद्यमों हेतु बैंक ऋण।', 'SC/ST or women entrepreneurs (18+) setting up a new manufacturing/services/trading enterprise.', 'नया विनिर्माण/सेवा/व्यापार उद्यम स्थापित करने वाले SC/ST या महिला उद्यमी (18+)।', 'Bank loan', 'Bank loans ₹10 lakh–₹1 crore for greenfield projects. Verify current terms.', 'SC/ST and women entrepreneurs.', 'https://www.standupmitra.in', 'likely_active', 'Likely active — bank loans ₹10 lakh–₹1 crore for SC/ST and women entrepreneurs (greenfield); sanctions continued through Oct 2025 (₹62,807 cr cumulative, IBEF), but the notified scheme period ran to 2025 and a formal post-March-2025 extension was not confirmed. Verified 2026-06-19. Source: https://www.standupmitra.in/', NULL, NULL, 'https://www.standupmitra.in', '2026-06-19', NULL, '2026-06-19 18:23:33.640011+05:30', '{self_employed_entrepreneur}', '{}', 'any', '{}', 18, NULL, NULL, false, 'any', false, false, NULL, NULL, '{financial_inclusion,industry}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('87f0a579-c07f-4186-af13-fa43f75d47f4', 'Sukanya Samriddhi Yojana (SSY)', 'सुकन्या समृद्धि योजना (SSY)', '76bf5c89-0e98-4a01-98ff-d0de1281611f', NULL, 'Small-savings account for a girl child with attractive interest and tax benefits.', 'बालिका हेतु आकर्षक ब्याज एवं कर-लाभ वाला अल्प-बचत खाता।', 'Account opened by a guardian for a girl child below 10 years (max two girls per family, exceptions apply).', 'अभिभावक द्वारा 10 वर्ष से कम आयु की बालिका हेतु खाता (अधिकतम दो बालिकाएँ, अपवाद सहित)।', 'Small-savings account', 'Small-savings deposit for a girl child at 8.2% p.a. (Apr–Jun 2026) with EEE tax benefit; matures for her education/marriage.', 'Girl children (below 10).', 'https://www.nsiindia.gov.in', 'active', 'Active — small-savings rates retained, SSY at 8.2% for Q1 FY2026-27 (Finance Ministry, Mar 2026). Verified 2026-06-19. Source: https://www.nsiindia.gov.in/', NULL, NULL, 'https://www.nsiindia.gov.in', '2026-06-19', NULL, '2026-06-19 18:09:43.702752+05:30', '{}', '{}', 'female', '{}', NULL, NULL, NULL, false, 'any', false, false, NULL, NULL, '{financial_inclusion,women_child}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('9df62d2e-a4a8-49aa-95dd-995c633f2659', 'Housing Accommodation for Women Government Employees (near place of posting)', 'महिला सरकारी कर्मियों हेतु आवास सुविधा (पदस्थापन स्थल के निकट)', '63ae0f53-396e-45ad-a075-91a929575767', NULL, 'Provide safe, affordable rental accommodation to women state-government employees at or near their place of posting — especially those serving in rural and block-level offices — to improve their safety and convenience. Where government quarters are unavailable, the state leases private housing for them.', 'महिला राज्य-सरकारी कर्मियों को उनके पदस्थापन स्थल पर या उसके निकट सुरक्षित एवं किफायती किराया आवास उपलब्ध कराना — विशेषकर ग्रामीण एवं प्रखंड-स्तरीय कार्यालयों में कार्यरत महिलाओं को — ताकि उनकी सुरक्षा एवं सुविधा बढ़े। जहाँ सरकारी आवास उपलब्ध न हो, वहाँ सरकार उनके लिए निजी आवास पट्टे पर लेगी।', 'Women employees of the Bihar state government posted in the state — reported to include schoolteachers, women officers and staff, police personnel, and women working from the panchayat level up to the secretariat. Priority emphasis on those posted at rural / block-level offices. Employees opting for this government-provided accommodation forgo House Rent Allowance (HRA).', 'बिहार राज्य सरकार की महिला कर्मी जो राज्य में पदस्थापित हैं — समाचारों के अनुसार इसमें शिक्षिकाएँ, महिला अधिकारी एवं कर्मचारी, पुलिसकर्मी, तथा पंचायत स्तर से सचिवालय तक कार्यरत महिलाएँ शामिल हैं। ग्रामीण / प्रखंड-स्तरीय कार्यालयों में पदस्थापित महिलाओं को प्राथमिकता। यह सरकारी आवास चुनने वाली कर्मी मकान किराया भत्ता (HRA) नहीं लेंगी।', 'Leased rental accommodation (in lieu of HRA)', 'Rent-free or government-leased private accommodation near the employee''s posting, arranged by a district-level committee chaired by the District Magistrate, which identifies suitable buildings (with electricity, water, sanitation and structural safety) and executes lease agreements with landlords; the Sub-Divisional Officer (SDO) finalises the rent and handles grievances. Rollout is phased — beginning at district and divisional headquarters before expanding. Specific rent ceilings have not been published.', 'Women employees of the Bihar state government, especially those in rural/block-level postings.', NULL, 'likely_active', 'Likely active — approved by the Bihar Cabinet on 10 June 2025 (chaired by CM Nitish Kumar) to provide accommodation near posting for ~4 lakh women government employees. As of verification the scheme is in early rollout: implementing departments are to begin formalities, district committees and landlord expressions-of-interest are the delivery mechanism, and no application portal, budget line, or formal operating guidelines have been published yet. No official government notification/PDF located — sourced from news coverage of the cabinet decision; replace source_url with the official notification when available. Verified 2026-06-25.', NULL, '2025-06-10', 'https://www.hrkatha.com/news/bihar-cabinet-approves-housing-for-women-staff-near-workplaces/', '2026-06-25', NULL, '2026-06-25 16:30:16.225907+05:30', '{salaried_employee}', '{}', 'female', '{}', NULL, NULL, NULL, false, 'bihar', false, false, NULL, NULL, '{housing,women_child,social_welfare}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('36a1041b-d3dd-40ff-9b15-4b5da63ce9a6', 'Indira Awaas Yojana (IAY)', 'इंदिरा आवास योजना (IAY)', '76bf5c89-0e98-4a01-98ff-d0de1281611f', NULL, 'Earlier central rural housing scheme providing assistance to BPL families to build houses.', 'BPL परिवारों को मकान निर्माण हेतु सहायता देने वाली पूर्ववर्ती केंद्रीय ग्रामीण आवास योजना।', 'Rural BPL families (historical scheme).', 'ग्रामीण BPL परिवार (ऐतिहासिक योजना)।', 'Housing assistance', 'Provided grant assistance for rural house construction (now under PMAY-G).', 'Rural BPL families.', NULL, 'subsumed', 'Subsumed — Indira Awaas Yojana was restructured into Pradhan Mantri Awaas Yojana–Gramin with effect from 1 Apr 2016 (PMAY-G launched 20 Nov 2016). Apply under PMAY-G. Verified 2026-06-19. Source: https://pmayg.nic.in/', NULL, NULL, 'https://rural.gov.in', '2026-06-19', NULL, '2026-06-19 18:13:52.058776+05:30', '{}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'any', false, false, NULL, '1ea75d8d-b5f7-46f2-834c-31ab3faffc24', '{housing,social_welfare}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('d9f43648-a2da-48d4-8cfc-aeb63e17a433', 'Mukhyamantri Balika Protsahan Yojana (Intermediate)', 'मुख्यमंत्री बालिका प्रोत्साहन योजना (इंटरमीडिएट)', 'c6f71956-defd-4037-8324-6c3e805899ba', NULL, 'One-time incentive for girls who pass the Class 12 (Intermediate) BSEB exam.', 'बिहार बोर्ड से 12वीं (इंटरमीडिएट) उत्तीर्ण बालिकाओं हेतु एकमुश्त प्रोत्साहन।', 'Girls of Bihar passing Class 12 from BSEB.', 'बिहार बोर्ड से 12वीं उत्तीर्ण बिहार की बालिकाएँ।', 'Cash incentive', 'Reported ₹25,000 one-time. Verify at the portal.', 'Girls passing Class 12 in Bihar.', 'https://www.medhasoft.bihar.gov.in', 'subsumed', 'Subsumed — the intermediate-pass girls'' incentive is now administered as the intermediate milestone of the Mukhyamantri Kanya Utthan Yojana (₹25,000 first division / ₹15,000 second division, via medhasoft). Apply under Kanya Utthan. Verified 2026-06-19. Source: https://medhasoft.bihar.gov.in/', NULL, NULL, 'https://www.medhasoft.bihar.gov.in', '2026-06-19', NULL, '2026-06-19 17:38:29.835346+05:30', '{student}', '{senior_secondary}', 'female', '{}', NULL, NULL, NULL, false, 'bihar', false, false, NULL, '69d8804c-688c-4ac5-8f74-cb6c650dbd62', '{education,women_child}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('3f38ab68-1292-4abb-9da7-aba6399e6798', 'Rajiv Awas Yojana (RAY)', 'राजीव आवास योजना (RAY)', '76bf5c89-0e98-4a01-98ff-d0de1281611f', NULL, 'Earlier central scheme towards a slum-free India / urban housing for the poor.', 'झुग्गी-मुक्त भारत / शहरी निर्धन आवास हेतु पूर्ववर्ती केंद्रीय योजना।', 'Urban slum dwellers / poor (historical scheme).', 'शहरी झुग्गीवासी / निर्धन (ऐतिहासिक योजना)।', 'Urban housing', 'Supported slum redevelopment / urban housing (now under PMAY-Urban).', 'Urban poor / slum dwellers.', NULL, 'subsumed', 'Subsumed — Rajiv Awas Yojana was discontinued by Ministry order dated 19 May 2015 and its liabilities folded into the Housing for All mission (PMAY-Urban, launched Jun 2015). Verified 2026-06-19. Source: https://pmay-urban.gov.in/', NULL, NULL, 'https://mohua.gov.in', '2026-06-19', NULL, '2026-06-19 18:13:52.063069+05:30', '{}', '{}', 'any', '{}', NULL, NULL, NULL, false, 'any', false, false, NULL, 'dd7ca793-5bce-4f4a-9d4d-86122bb5977d', '{housing}');
INSERT INTO public.schemes (id, name_en, name_hi, department_id, launch_date, objective_en, objective_hi, eligibility_en, eligibility_hi, benefit_type, benefit_detail, target_beneficiary, application_portal_url, status, status_evidence, last_budget_year, last_notification_date, source_url, last_verified, embedding, created_at, personas, education_levels, gender_eligibility, social_categories, min_age, max_age, income_ceiling, requires_bpl, domicile, is_for_disabled, is_for_startups, land_ownership, successor_scheme_id, categories) VALUES ('a8a063cf-08ed-449e-a703-e26ddc2579ce', 'Pradhan Mantri Ujjwala Yojana (PMUY)', 'प्रधानमंत्री उज्ज्वला योजना (PMUY)', '76bf5c89-0e98-4a01-98ff-d0de1281611f', NULL, 'Free LPG (cooking gas) connection to women of poor / eligible households.', 'निर्धन/पात्र परिवारों की महिलाओं को नि:शुल्क एलपीजी (रसोई गैस) कनेक्शन।', 'Adult woman of an eligible low-income household without an existing LPG connection.', 'पात्र निम्न-आय परिवार की वयस्क महिला जिसके पास पहले से एलपीजी कनेक्शन न हो।', 'Free LPG connection', 'Free LPG connection with deposit support (₹1,700 / ₹950) plus first refill and stove; subsidy of ₹300 per 14.2 kg cylinder for up to 9 refills/year (FY2025-26).', 'Women of eligible low-income households.', 'https://www.pmuy.gov.in', 'active', 'Active — Cabinet continued the targeted subsidy for FY2025-26 (₹12,000 cr); ~10.56 crore connections. Verified 2026-06-19. Source: https://www.pmuy.gov.in/', NULL, NULL, 'https://www.pmuy.gov.in', '2026-06-19', NULL, '2026-06-19 18:09:43.694563+05:30', '{widow}', '{}', 'female', '{}', NULL, NULL, NULL, false, 'any', false, false, NULL, NULL, '{social_welfare,women_child,health}');
