INSERT INTO public.policies (id, name_en, name_hi, department_id, summary_en, summary_hi, period_start, period_end, status, superseded_by, source_url, last_verified, created_at, categories, policy_type, document_url, is_draft, consultation_url, consultation_start, consultation_end, how_to_comment_en, how_to_comment_hi) VALUES ('35ed0080-2a10-4e76-8b6a-e4462beff2ae', 'Bihar Electric Vehicle (EV) Policy 2023', 'बिहार इलेक्ट्रिक वाहन (EV) नीति 2023', '656e1179-0bc5-45c0-b0b2-da0acbce5907', 'Aims for 15% EVs in all vehicle registrations by 2028. Offers up to 75% Motor Vehicle Tax subsidy and purchase incentives up to ₹1.25 lakh for the first 1,000 personal four-wheeler EVs, plus support for charging infrastructure.', '2028 तक सभी वाहन पंजीकरण में 15% EV का लक्ष्य। 75% तक मोटर वाहन कर सब्सिडी एवं पहले 1,000 निजी चार-पहिया EV हेतु ₹1.25 लाख तक खरीद प्रोत्साहन, साथ ही चार्जिंग अवसंरचना हेतु सहायता।', NULL, NULL, 'active', NULL, 'https://www.deccanherald.com/india/bihar/bihar-cabinet-approves-new-electric-vehicle-policy-2797868', '2026-06-19', '2026-06-19 14:07:56.101933+05:30', '{industry}', 'framework', NULL, false, NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.policies (id, name_en, name_hi, department_id, summary_en, summary_hi, period_start, period_end, status, superseded_by, source_url, last_verified, created_at, categories, policy_type, document_url, is_draft, consultation_url, consultation_start, consultation_end, how_to_comment_en, how_to_comment_hi) VALUES ('6a383344-ecdf-4cd8-9c8b-9c615366d17e', 'Bihar Export Promotion Policy 2024', 'बिहार निर्यात प्रोत्साहन नीति 2024', '656e1179-0bc5-45c0-b0b2-da0acbce5907', 'Policy to boost exports from Bihar through incentives and export infrastructure. Listed among the state''s 2024 industrial policies; verify scope and incentives against the official document.', 'प्रोत्साहन एवं निर्यात अवसंरचना के माध्यम से बिहार से निर्यात बढ़ाने की नीति। विवरण आधिकारिक दस्तावेज़ से सत्यापित करें।', NULL, NULL, 'active', NULL, 'https://hebe.net.in/industries-policies/', '2026-06-19', '2026-06-19 14:07:56.101359+05:30', '{industry}', 'framework', NULL, false, NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.policies (id, name_en, name_hi, department_id, summary_en, summary_hi, period_start, period_end, status, superseded_by, source_url, last_verified, created_at, categories, policy_type, document_url, is_draft, consultation_url, consultation_start, consultation_end, how_to_comment_en, how_to_comment_hi) VALUES ('d9d3a915-5854-4b1c-8f3b-5eb05998521c', 'Bihar Industrial Investment Promotion Package (BIPPP) 2025', 'बिहार औद्योगिक निवेश प्रोत्साहन पैकेज (BIPPP) 2025', '656e1179-0bc5-45c0-b0b2-da0acbce5907', 'Industrial promotion package approved by the state cabinet (Aug 2025): land concessions, capital subsidy up to 30%, interest subvention up to ₹40 cr, and free land allotment scaled to investment size (10 acres for >₹100 cr up to 25 acres for >₹1,000 cr). Cross-check details against the official notification.', 'राज्य कैबिनेट द्वारा स्वीकृत औद्योगिक प्रोत्साहन पैकेज (अगस्त 2025): भूमि रियायतें, 30% तक पूंजी सब्सिडी, ₹40 करोड़ तक ब्याज अनुदान, एवं निवेश-आकार के अनुसार नि:शुल्क भूमि आवंटन। विवरण आधिकारिक अधिसूचना से सत्यापित करें।', NULL, NULL, 'active', NULL, 'https://www.newsonair.gov.in/bihar-state-gov-has-approved-new-bihar-industrial-investment-promotion-package', '2026-06-19', '2026-06-19 14:07:56.10058+05:30', '{industry}', 'package', NULL, false, NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.policies (id, name_en, name_hi, department_id, summary_en, summary_hi, period_start, period_end, status, superseded_by, source_url, last_verified, created_at, categories, policy_type, document_url, is_draft, consultation_url, consultation_start, consultation_end, how_to_comment_en, how_to_comment_hi) VALUES ('71f2da7f-37ca-4ffc-92f6-e4720a3b4563', 'Bihar IT Policy 2024', 'बिहार आईटी नीति 2024', '66d6b451-405f-4666-a26d-94bcc46f1047', 'Framework to attract investment and employment in IT/ITeS and ESDM. Offers fiscal incentives including up to 30% capital subsidy (capped at ₹30 cr), 10% interest subvention, 50% lease-rental subsidy, 25% power-tariff reimbursement, and EPF/ESI reimbursement — all for up to 5 years.', 'आईटी/आईटीईएस एवं ESDM क्षेत्र में निवेश व रोज़गार आकर्षित करने हेतु रूपरेखा। 30% तक पूंजी सब्सिडी (अधिकतम ₹30 करोड़), 10% ब्याज अनुदान, 50% लीज-किराया सब्सिडी, 25% बिजली-शुल्क प्रतिपूर्ति एवं EPF/ESI प्रतिपूर्ति — सभी 5 वर्ष तक।', '2024-01-09', '2029-12-08', 'active', NULL, 'https://patnapress.com/bihar-unveils-ambitious-it-policy-2024-to-propel-investment-and-employment-in-the-it-ites-and-esdm-sector/', '2026-06-19', '2026-06-19 14:07:56.097492+05:30', '{industry}', 'framework', 'https://hebe.net.in/wp-content/uploads/2024/06/Highlights_of_Bihar_IT_policy-1.pdf', false, NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.policies (id, name_en, name_hi, department_id, summary_en, summary_hi, period_start, period_end, status, superseded_by, source_url, last_verified, created_at, categories, policy_type, document_url, is_draft, consultation_url, consultation_start, consultation_end, how_to_comment_en, how_to_comment_hi) VALUES ('55da2a3b-5263-49f6-a4e4-4f9b34b0a2d7', 'Bihar Krishi Road Map (Agriculture Roadmap)', 'बिहार कृषि रोड मैप', '77fa7e43-0589-4b9b-8807-bbafc0146d67', 'Bihar''s multi-year agriculture framework coordinating input subsidies, mechanisation, horticulture, irrigation and farmer income support across the farm sector.', 'बिहार की बहु-वर्षीय कृषि रूपरेखा जो इनपुट अनुदान, यंत्रीकरण, बागवानी, सिंचाई एवं किसान आय-सहायता का समन्वय करती है।', NULL, NULL, 'active', NULL, 'https://krishi.bih.nic.in', '2026-06-19', '2026-06-19 17:50:07.581962+05:30', '{agriculture}', 'framework', NULL, false, NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.policies (id, name_en, name_hi, department_id, summary_en, summary_hi, period_start, period_end, status, superseded_by, source_url, last_verified, created_at, categories, policy_type, document_url, is_draft, consultation_url, consultation_start, consultation_end, how_to_comment_en, how_to_comment_hi) VALUES ('c411b1c1-7c42-4577-9aea-01e22196c998', 'Bihar Draft Rules under the Labour Codes, 2025', 'श्रम संहिता के अंतर्गत बिहार प्रारूप नियम, 2025', '896891da-f714-41d6-b6bb-fd84e5ecfb00', 'Draft rules to operationalise the four central Labour Codes (Wages; Industrial Relations; Social Security; Occupational Safety, Health & Working Conditions) in Bihar. Notified for public objections and suggestions (an extended period was notified). Open for public comment — confirm the current deadline and submission address in the official notification.', 'बिहार में चार केंद्रीय श्रम संहिताओं (वेतन; औद्योगिक संबंध; सामाजिक सुरक्षा; व्यावसायिक सुरक्षा, स्वास्थ्य एवं कार्यदशा) को लागू करने हेतु प्रारूप नियम। आम जनता से आपत्ति एवं सुझाव हेतु अधिसूचित। टिप्पणी हेतु खुला — वर्तमान समय-सीमा व पता आधिकारिक अधिसूचना से सत्यापित करें।', NULL, NULL, 'unknown', NULL, 'https://www.simpliance.in/India/LEI/govt_notification/Bihar/notification-regarding-draft-rules-of-various-labour-codes-2025-have-been-formulated-and-regarding-the-extended-period-for-objections-and-suggestions-from-the-general-public-as-per-the-provisions-of-the-code-hindi-version-8763', '2026-06-19', '2026-06-19 14:07:56.102813+05:30', '{employment}', 'rules', 'https://www.simpliance.in/India/LEI/govt_notification/Bihar/notification-regarding-draft-rules-of-various-labour-codes-2025-have-been-formulated-and-regarding-the-extended-period-for-objections-and-suggestions-from-the-general-public-as-per-the-provisions-of-the-code-hindi-version-8763', true, 'https://state.bihar.gov.in/labour', NULL, NULL, '1. Read the draft rules (document link). 2. Write your objection/suggestion citing the specific rule number. 3. Send it to the Labour Resources Department, Government of Bihar, within the notified period. 4. Confirm the current deadline and exact submission address (email/post) in the official notification before sending.', '1. प्रारूप नियम पढ़ें (दस्तावेज़ लिंक)। 2. संबंधित नियम संख्या का उल्लेख करते हुए अपनी आपत्ति/सुझाव लिखें। 3. इसे अधिसूचित अवधि के भीतर श्रम संसाधन विभाग, बिहार सरकार को भेजें। 4. भेजने से पूर्व वर्तमान समय-सीमा एवं सटीक पता (ईमेल/डाक) आधिकारिक अधिसूचना से सत्यापित करें।');
INSERT INTO public.policies (id, name_en, name_hi, department_id, summary_en, summary_hi, period_start, period_end, status, superseded_by, source_url, last_verified, created_at, categories, policy_type, document_url, is_draft, consultation_url, consultation_start, consultation_end, how_to_comment_en, how_to_comment_hi) VALUES ('937d43a9-6434-4d22-87dc-43be4d8794eb', 'Bihar Logistics Policy 2024', 'बिहार लॉजिस्टिक्स नीति 2024', '656e1179-0bc5-45c0-b0b2-da0acbce5907', 'State logistics policy to develop warehousing, multimodal infrastructure and logistics parks. Listed among Bihar''s 2024 industrial-promotion policies; verify scope and incentives against the official policy document.', 'भंडारण, बहुविध अवसंरचना एवं लॉजिस्टिक्स पार्क विकसित करने हेतु राज्य लॉजिस्टिक्स नीति। विवरण आधिकारिक नीति दस्तावेज़ से सत्यापित करें।', NULL, NULL, 'active', NULL, 'https://hebe.net.in/industries-policies/', '2026-06-19', '2026-06-19 14:07:56.10104+05:30', '{industry}', 'framework', NULL, false, NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.policies (id, name_en, name_hi, department_id, summary_en, summary_hi, period_start, period_end, status, superseded_by, source_url, last_verified, created_at, categories, policy_type, document_url, is_draft, consultation_url, consultation_start, consultation_end, how_to_comment_en, how_to_comment_hi) VALUES ('d71a0735-3705-49e7-87fb-cc23e4c3bd9e', 'Bihar Semiconductor Policy 2026', 'बिहार सेमीकंडक्टर नीति 2026', '656e1179-0bc5-45c0-b0b2-da0acbce5907', 'Recently announced policy to build a semiconductor/electronics ecosystem in Bihar, part of the state''s 2026 industrial and technology push. Verify incentives and scope against the official policy document.', 'बिहार में सेमीकंडक्टर/इलेक्ट्रॉनिक्स पारिस्थितिकी तंत्र बनाने हेतु हाल में घोषित नीति। प्रोत्साहन एवं दायरा आधिकारिक दस्तावेज़ से सत्यापित करें।', NULL, NULL, 'active', NULL, 'https://yourstory.com/2026/03/bihar-startup-industrial-ecosystem-policy-investment-growth', '2026-06-19', '2026-06-19 14:07:56.102344+05:30', '{industry}', 'framework', NULL, false, NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.policies (id, name_en, name_hi, department_id, summary_en, summary_hi, period_start, period_end, status, superseded_by, source_url, last_verified, created_at, categories, policy_type, document_url, is_draft, consultation_url, consultation_start, consultation_end, how_to_comment_en, how_to_comment_hi) VALUES ('16b17e93-3195-4c1f-8f99-4a60667a5f0c', 'Bihar Social Security Pensions (SSPMIS)', 'बिहार सामाजिक सुरक्षा पेंशन (SSPMIS)', '3df327f2-b1bf-440d-a46f-840341a10329', 'The state''s social-security pension framework (delivered via SSPMIS) covering the elderly, persons with disabilities and widows through monthly DBT pensions.', 'राज्य की सामाजिक-सुरक्षा पेंशन रूपरेखा (SSPMIS के माध्यम से) जो वृद्धजनों, दिव्यांगजनों एवं विधवाओं को मासिक DBT पेंशन देती है।', NULL, NULL, 'active', NULL, 'https://www.sspmis.bihar.gov.in', '2026-06-19', '2026-06-19 17:50:07.589997+05:30', '{social_welfare}', 'mission', NULL, false, NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.policies (id, name_en, name_hi, department_id, summary_en, summary_hi, period_start, period_end, status, superseded_by, source_url, last_verified, created_at, categories, policy_type, document_url, is_draft, consultation_url, consultation_start, consultation_end, how_to_comment_en, how_to_comment_hi) VALUES ('c8c1f6fb-3b6f-46a2-9409-30d24169d648', 'Bihar Startup Policy 2022', 'बिहार स्टार्टअप नीति 2022', '656e1179-0bc5-45c0-b0b2-da0acbce5907', 'Framework to build Bihar''s startup ecosystem: interest-free seed funding up to ₹10 lakh (₹10.5 lakh for women; ₹11.5 lakh for SC/ST/PwD founders) over 10 years, a ₹3 lakh enhancement/training grant, plus mentoring and incubation support. Released against milestones.', 'बिहार के स्टार्टअप पारिस्थितिकी तंत्र हेतु रूपरेखा: 10 वर्ष के लिए ₹10 लाख तक ब्याज-मुक्त सीड फंडिंग (महिला ₹10.5 लाख; SC/ST/दिव्यांग ₹11.5 लाख), ₹3 लाख प्रशिक्षण/उन्नयन अनुदान, साथ ही मेंटरिंग व इन्क्यूबेशन सहायता।', NULL, NULL, 'active', NULL, 'https://udyogmitrabihar.in/bihar-startup-policy-2022/', '2026-06-19', '2026-06-19 17:07:53.526714+05:30', '{industry}', 'framework', 'https://hebe.net.in/highlights-of-bihar-startup-policy-2022/', false, NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.policies (id, name_en, name_hi, department_id, summary_en, summary_hi, period_start, period_end, status, superseded_by, source_url, last_verified, created_at, categories, policy_type, document_url, is_draft, consultation_url, consultation_start, consultation_end, how_to_comment_en, how_to_comment_hi) VALUES ('03232a5f-46b9-4446-bd42-0c8db6312002', 'Saat Nishchay-2 — Yuva Upmission', 'सात निश्चय-2 — युवा उपमिशन', 'b4cdf34b-599a-4ee4-9d31-cecac8488797', 'Bihar''s ''Seven Resolves'' (Saat Nishchay) governance vision. The youth resolve drives higher-education access, a job-search allowance and employability skilling — delivered through the Student Credit Card, Self-Help Allowance (MNSSBY) and Kushal Yuva Program.', 'बिहार की ''सात निश्चय'' शासन दृष्टि। युवा निश्चय उच्च शिक्षा तक पहुँच, रोज़गार-खोज भत्ता एवं रोज़गार-योग्यता कौशल को प्रेरित करता है — स्टूडेंट क्रेडिट कार्ड, स्वयं सहायता भत्ता (MNSSBY) एवं कुशल युवा कार्यक्रम के माध्यम से।', NULL, NULL, 'active', NULL, 'https://www.7nishchay-yuvaupmission.bihar.gov.in/', '2026-06-19', '2026-06-19 17:10:04.833636+05:30', '{employment,education}', 'mission', NULL, false, NULL, NULL, NULL, NULL, NULL);
INSERT INTO public.policies (id, name_en, name_hi, department_id, summary_en, summary_hi, period_start, period_end, status, superseded_by, source_url, last_verified, created_at, categories, policy_type, document_url, is_draft, consultation_url, consultation_start, consultation_end, how_to_comment_en, how_to_comment_hi) VALUES ('63019dc9-c96a-4620-acc5-f12dc16c254f', 'Bihar Industrial Investment Promotion Policy 2016', 'बिहार औद्योगिक निवेश प्रोत्साहन नीति 2016', '656e1179-0bc5-45c0-b0b2-da0acbce5907', 'Bihar''s 2016 framework of incentives for industrial investment (capital subsidy, interest subvention, tax-related benefits). Continued/replaced by the 2025 Industrial Investment Promotion Package.', 'औद्योगिक निवेश हेतु प्रोत्साहनों की बिहार की 2016 रूपरेखा (पूंजी सब्सिडी, ब्याज अनुदान, कर-संबंधी लाभ)। 2025 औद्योगिक निवेश प्रोत्साहन पैकेज द्वारा निरंतर/प्रतिस्थापित।', '2016-01-01', NULL, 'superseded', 'd9d3a915-5854-4b1c-8f3b-5eb05998521c', 'https://state.bihar.gov.in/cache/26/Documents/Bihar-Industrial-Investment-Policy-2016.pdf', '2026-06-19', '2026-06-19 14:30:45.214028+05:30', '{industry}', 'framework', 'https://state.bihar.gov.in/cache/26/Documents/Bihar-Industrial-Investment-Policy-2016.pdf', false, NULL, NULL, NULL, NULL, NULL);
